INSERT INTO `news` VALUES ('1', 'hot', '习近平会见尼泊尔总理奥利', 'https://news.sina.com.cn/zx/2024-12-03/doc-incyevpi1503177.shtml', null, '12月3日，国家主席习近平在北京钓鱼台国宾馆会见来华访问的尼泊尔总理奥利。双方强调中尼友好关系，计划深化在“一带一路”框架下的合作，加强互联互通和经济合作，并发表了联合声明。奥利重申尼方支持一个中国原则，不干涉中国内政。', '2025-02-28 21:24:23');
INSERT INTO `news` VALUES ('2', 'hot', '四大行业协会发声：美国芯片产品不再安全', 'https://news.sina.com.cn/o/2024-12-03/doc-incyerfr4838785.shtml', null, '美国宣布对140余家中国企业实施新的出口限制措施后，中国互联网协会、半导体行业协会、汽车行业协会及通信企业协会发布声明，坚决反对，并呼吁国内企业审慎采购美芯片，扩大与其他国家和地区的合作。这些协会指出，美国的单边主义行为损害了中美两国企业和全球供应链，并动摇了业界对美国产品的信心。', '2025-02-28 21:24:23');
INSERT INTO `news` VALUES ('3', 'hot', '中方是否会在台周边举行军演？外交部回应', 'https://news.sina.com.cn/c/2024-12-03/doc-incyekxt4879072.shtml', null, '外交部表示坚决反对任何形式的美台官方往来及美方支持“台独”行为，并强调台湾问题是核心利益。针对立陶宛宣布中国驻立代办处3名工作人员为“不受欢迎的人”，中方强烈谴责，同时希望立新政府以实际行动改善双边关系。', '2025-02-28 21:24:23');
INSERT INTO `news` VALUES ('4', 'hot', '为什么针对美国加强两用物项出口管制？', 'https://news.sina.com.cn/c/2024-12-03/doc-incyekxt4899270.shtml', null, '商务部决定加强相关两用物项对美出口管制，禁止对美国军事用户或用途出口，并严格限制镓、锗、锑、超硬材料和石墨等两用物项的对美出口，以维护国家安全利益及履行防扩散国际义务。任何违反规定的组织和个人将被追究责任。', '2025-02-28 21:24:23');
INSERT INTO `news` VALUES ('5', 'hot', '特鲁多和特朗普谈了什么？细节浮出水面', 'https://news.sina.com.cn/w/2024-12-03/doc-incyekxt4900309.shtml', null, '加拿大总理特鲁多突访当选总统特朗普的庄园，旨在阻止对加拿大征收关税。会上讨论了芬太尼、移民和贸易等问题。特朗普威胁若不解决边境安全及贸易逆差问题，将对所有加拿大商品征25%关税。尽管会谈中不乏玩笑，但特朗普明确表示希望在就任前改变现状。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('6', 'hot', '湖北十堰药王谷抗癌中心被“全面调查”', 'https://news.sina.com.cn/o/2024-12-03/doc-incyeerx1707485.shtml', null, '湖北药王谷一家中医诊所因被曝光“开诊一个月内15人死亡”受到广泛关注。武当山特区相关部门已依法立案调查此事，并将及时通报结果。该诊所宣称有“抗癌秘方”，但被曝出多名患者治疗后病情恶化或死亡，且存在违规诊疗行为和非卫生技术人员从事医疗卫生技术等问题。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('7', 'china', '中国互联网协会：呼吁国内企业审慎选择采购美国芯片', 'https://news.sina.com.cn/c/2024-12-03/doc-incyerfn8355528.shtml', null, '美国加大对华半导体出口限制，中国互联网协会对此表示反对，并呼吁国内企业减少对美芯片依赖，积极与其他国家合作。多家A股公司回应称影响可控，供应链已基本国产化。专家认为，这促使国内半导体产业链更加注重自主安全和扶持上游供应商发展。\n\n以上总结控制在了100字以内。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('8', 'china', '巡视组进驻，省公安厅原副厅长落马！首次披露', 'https://news.sina.com.cn/c/2024-12-03/doc-incyezvh8151107.shtml', null, '湖北省公安厅原党委委员、副厅长干永平涉嫌徇私枉法、受贿及利用影响力受贿案由湖北省人民检察院侦查终结并移送武汉市人民检察院审查起诉。干永平曾长期任职省公安厅，现已退休三年，被查后被开除党籍，并通报其存在多项违纪违法行为。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('9', 'china', '今日辟谣（2024年12月3日）', 'https://news.sina.com.cn/c/2024-12-03/doc-incyerfm1579968.shtml', null, '天津2024年“小升初”继续实行免试就近入学政策，无变化。艾滋病不会通过日常接触传播，应消除对HIV感染者的歧视。共享单车出现多个二维码，建议用户仔细辨别，避免扫描不明来源的二维码以保护自身权益。（98字）', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('10', 'china', '商务部公告：加强相关两用物项对美国出口管制', 'https://news.sina.com.cn/c/2024-12-03/doc-incyekxv1669486.shtml', null, '商务部发布公告，依据《中华人民共和国出口管制法》等法规，为维护国家安全及履行国际义务，决定加强两用物项对美国出口管制。具体措施包括禁止对美军事用途出口、原则上不许可镓、锗等特定物项的出口，并加强对石墨物项的最终用户和用途审查。违反规定将被追究法律责任。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('11', 'china', '“福宝”出现状况异常，中国大熊猫保护研究中心回应', 'https://news.sina.com.cn/c/2024-12-03/doc-incyekxt4864636.shtml', null, '12月3日，“福宝发抖”话题登上热搜第一。中国大熊猫保护研究中心表示，发现大熊猫“福宝”出现异常状况，正计划进行全面检查以确定原因，并将及时公布最新情况。“福宝”是首只在韩国出生的大熊猫，于今年4月返回中国。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('12', 'china', '我国成功发射通信技术试验卫星十三号', 'https://news.sina.com.cn/c/2024-12-03/doc-incyekxv1626811.shtml', null, '我国于2024年12月3日使用长征三号乙运载火箭，在西昌卫星发射中心成功发射通信技术试验卫星十三号，该卫星将用于卫星通信、广播电视和数据传输等业务。此次发射是长征系列运载火箭的第549次飞行。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('13', 'china', '最高人民检察院依法对王昊决定逮捕', 'https://news.sina.com.cn/c/2024-12-03/doc-incycyiu8561373.shtml', null, '江苏省政协原党组成员、副主席王昊因涉嫌受贿已被国家监察委员会调查终结，并由最高人民检察院作出逮捕决定。此前，中央纪委国家监委查明其存在严重违纪违法行为，已给予其开除党籍和公职处分，并将其涉嫌犯罪问题移送检察机关审查起诉。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('14', 'china', '国家发改委：完善成品油管道运输价格形成机制', 'https://news.sina.com.cn/c/2024-12-03/doc-incyctzz5116937.shtml', null, '国家发改委发布通知，完善跨省成品油管道运输价格形成机制，采用弹性监管机制，由国家核定最高准许收入，企业与用户协商确定具体价格。机制包括“准许成本加合理收益”原则的最高准许收入核定方法、3年一周期的价格调整，及保障供应和降低运输成本等要求，自2025年1月1日起实施。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('15', 'china', '航行警告！南海部分海域进行实弹射击 禁止驶入', 'https://news.sina.com.cn/c/2024-12-03/doc-incycuac1884459.shtml', null, '广东海事局发布航行警告，12月3日8时至16时，南海特定区域将进行实弹射击演习，此期间禁止船舶进入该海域。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('16', 'china', '外交部强烈谴责立陶宛 立陶宛到底怎么回事？', 'https://news.sina.com.cn/c/2024-12-03/doc-incyctzv1890087.shtml', null, '立陶宛看守政府在外交部例行记者会上被中国强烈谴责和反对。11月29日，立陶宛宣布将中国驻立代办处外交人员列为“不受欢迎的人”，要求限期离境，此举被视为粗暴挑衅。此前，由于涉台问题严重违反一个中国原则，中立关系已经陷入困境三年。中方希望新成立的立陶宛政府能坚持一个中国原则，推动双边关系重回正轨。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('17', 'china', '多地党政主官“抓足球”：这是“难而正确”的事', 'https://news.sina.com.cn/c/2024-12-03/doc-incycuac1881934.shtml', null, '近期，浙江、江苏等地党政主官积极支持足球发展工作，通过观看比赛和深入调研推动地方足球事业。杭州市委书记刘捷与市长姚高员多次参与并强调青少年足球人才培养的重要性；温州市委书记张振丰也表示将加速打造运动之城，推进温州足球改革。江苏省长许昆林等领导出席了江苏足球发展重点城市对抗赛，旨在通过城市间竞赛促进全省足球文化氛围和运动发展。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('18', 'china', '诺如病毒感染进入高发期！国家疾控局紧急提醒', 'https://news.sina.com.cn/c/2024-12-03/doc-incyctzs7986691.shtml', null, '近日，我国多地发生诺如病毒群体感染事件，该病毒引起的急性感染性腹泻已进入发病高峰期。中国疾控中心专家指出，诺如病毒传染性强，目前无特效药物和疫苗可用。11月30日，国家疾控局发布防控消毒技术指南，强调酒精对诺如病毒无效，并指导学校等重点场所做好预防措施。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('19', 'china', 'WTT成都混团世界杯今日赛程：国乒将迎战美国队', 'https://news.sina.com.cn/c/2024-12-03/doc-incyctzu4752183.shtml', null, '2024年成都国际乒联混合团体世界杯继续进行，中国乒乓球队将于北京时间12时对阵美国队。比赛采用15局8胜制，包括混双、女单、男单、女双和男双五项。中国队此前已连胜澳大利亚和印度队。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('20', 'world', '叙利亚乱局背后的“黑影”', 'https://news.sina.com.cn/w/2024-12-03/doc-incyezvm4630218.shtml', null, '叙利亚极端组织和反对派武装对政府军发起大规模进攻，被指受土耳其、以色列及美国支持。土耳其否认直接参与，但有消息指出，进攻背后得到乌克兰的培训和技术支持，以及以色列在战略上的“坐收渔利”。此次行动意图利用真主党和伊朗因与以色列停火协议而被削弱的机会，并可能影响中东地缘政治格局。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('21', 'world', '叙利亚政府军与库尔德武装交战 叙北部7个村庄遭袭', 'https://news.sina.com.cn/w/2024-12-03/doc-incyezvm4627215.shtml', null, '当地时间3日，在叙利亚代尔祖尔省，叙政府军与美军支持的库尔德武装交战。库尔德武装袭击了该省北部7个村庄，随后被叙政府军击退并控制局势。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('22', 'world', '又生变数！法国巴尼耶政府或遭投票下台', 'https://news.sina.com.cn/w/2024-12-03/doc-incyevpr1525614.shtml', null, '法国总理巴尼耶因启用宪法条款强行通过2025年社保预算案而遭遇极右翼政党“国民联盟”和左翼政党的不信任动议挑战，投票将于12月4日进行。专家分析指出，巴尼耶政府的政治基础脆弱，面临被弹劾的风险；总统马克龙需采取长远规划以应对当前政局动荡。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('23', 'world', '准备长期驻留？美媒曝以军在加沙地带中部兴建基地', 'https://news.sina.com.cn/w/2024-12-03/doc-incyerfr4791718.shtml', null, '以色列国防军在加沙地带中部加速扩建基地、铲平当地建筑，显示出其准备长期控制该地区。自去年10月巴以冲突爆发以来，以军已经控制了“内察里姆走廊”，并在此周边设立了至少19处军事基地，其中多处为今年新建或扩建。这些行动导致加沙地带大量房屋和设施被毁，给当地居民带来严重苦难。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('24', 'world', '泰国南部洪灾已造成25人死亡 超66万户居民受灾', 'https://news.sina.com.cn/w/2024-12-03/doc-incyekxv1629745.shtml', null, '泰国南部遭受严重洪涝灾害，6个府仍受洪水影响，已导致25人死亡，超66万户居民受灾。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('25', 'world', '美国钢铁收购案又遇波澜！特朗普：他将阻止这笔交易', 'https://news.sina.com.cn/w/2024-12-03/doc-incyekxp1665008.shtml', null, '美国当选总统唐纳德·特朗普重申反对日本制铁公司收购美国钢铁的计划，并表示就任后将阻止该交易。尽管日本制铁多次游说并承诺投资和成立以美国人占多数的董事会，CFIUS仍在审查这笔交易对国家安全的影响。特朗普强调他将阻止此交易，而拜登虽公开反对但未采取行动。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('26', 'world', '澳大利亚一男子持刀威胁公众安全 被警方击毙', 'https://news.sina.com.cn/w/2024-12-03/doc-incyeerx1746433.shtml', null, '12月3日，澳大利亚塔斯马尼亚州朗塞斯顿市中心发生一起持刀威胁事件。一名男子在公共场所威胁公众安全，在警方警告后仍拒绝配合并表现攻击性行为，最终被警方开枪击毙。目前无其他人员伤亡报告，事件正在调查中。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('27', 'world', '美国债务又要“爆”了？带给世界的风险攀升', 'https://news.sina.com.cn/w/2024-12-03/doc-incyeerv4948092.shtml', null, '特朗普新政府下，美国国债或将迎来爆炸式增长。国际金融协会预测，减税政策将增加数万亿美元赤字。尽管特朗普提名斯科特·贝森特为财政部长以遏制债务膨胀，但其所得税和企业税减免计划（如将企业税率降至15%）可能加剧问题。当前美国国家债务已超36万亿美元，高企的债务水平可能导致政府无法应对未来危机。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('28', 'world', '回击特朗普！欧委会副主席喊出了“欧洲优先”', 'https://news.sina.com.cn/w/2024-12-03/doc-incyeerx1724428.shtml', null, '欧委会执行副主席斯特凡纳·塞茹尔内呼吁欧盟制定“欧洲优先”战略，以应对潜在全球贸易战带来的风险。他强调必须促进欧洲的战略商业利益和发展本土产业，同时对美国可能引发的贸易冲突表示担忧，并计划在任期头100天内确定关键部门范围及整合欧盟资本市场。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('29', 'world', '盗抢衣物伤人 醉酒爬上民房 驻日美军连曝恶行', 'https://news.sina.com.cn/w/2024-12-03/doc-incyeerv4936383.shtml', null, '驻日美军近期犯罪事件频发，包括一名士兵偷窃衣物并打伤店员，另一名醉酒爬上居民家屋顶。这两起案件正在调查中，引发冲绳民众强烈不满。长期以来，驻日美军因享有一定的治外法权，其犯罪、交通肇事等问题常引起当地民怨。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('30', 'world', '特朗普声称将阻止日本制铁收购美国钢铁的交易', 'https://news.sina.com.cn/w/2024-12-03/doc-incycyiu8574018.shtml', null, '特朗普反对美国钢铁公司被日本制铁收购，承诺通过税收优惠和关税措施振兴美国钢铁，并表示将作为总统阻止该交易。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('31', 'finance', '美国发布半导体出口管制措施，商务部：严重威胁全球产业链供应链稳定', 'https://finance.sina.com.cn/jjxw/2024-12-03/doc-incyevpp4746392.shtml', null, '美国商务部发布对华半导体出口管制措施，新增136家中国实体至出口管制清单。中方对此表示反对，认为这是经济胁迫行为和非市场做法，将采取必要措施维护自身权益。此次管制涉及24类半导体制造设备、HBM存储器及软件工具等物项，并将推动国内半导体产业加速自主可控发展。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('32', 'finance', '突发！比特币，跳水跌破95000美元！16万人爆仓！', 'https://finance.sina.com.cn/jjxw/2024-12-03/doc-incyezvf1376076.shtml', null, '比特币跌破95000美元，市场对其后市走势存在分歧。尽管有超过16万人在过去24小时内爆仓，但大量资金仍流入比特币ETF，显示出对比特币的长期看好态度。贝莱德IBIT资产管理规模已突破50万枚比特币，MicroStrategy也增持了大量比特币。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('33', 'finance', '王毅：美国不要陷入“竞赢”中国的迷思', 'https://finance.sina.com.cn/jjxw/2024-12-03/doc-incyevpp4730961.shtml', null, '王毅在北京会见美国外交政策全国委员会会长埃利奥特一行时强调，中国坚持稳定和发展中美关系的三大原则不变，并提出确保中美关系稳定的四个方向。美方表示期待双方保持沟通，继续开展对话和人文交流以稳定两国关系。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('34', 'finance', '美国总统拜登离任前突访非洲，为什么？', 'https://finance.sina.com.cn/roll/2024-12-03/doc-incyevpp4739386.shtml', null, '拜登总统首次访问非洲，聚焦赞比亚、刚果和安哥拉的洛比托走廊铁路重建项目。此次访问包括会见安哥拉总统洛伦索及赞比亚总统希奇莱马，并计划公布对非洲医疗、气候和清洁能源项目的援助计划。美国支持的洛比托走廊铁路项目旨在改善资源出口，涉及8亿美元投资，由葡萄牙公司领导财团运营30年。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('35', 'finance', '金价大跌！报告认为黄金的长期上涨趋势仍未改变', 'https://finance.sina.com.cn/jjxw/2024-12-03/doc-incyerft1595569.shtml', null, '12月2日，现货黄金价格震荡下跌至2621.84美元/盎司，国际金价连续承压。美联储可能放慢降息步伐的预期及美国通胀数据停滞不前导致市场对进一步降息持谨慎态度，使金价受压。尽管短期内金价或继续承压，但高盛和瑞银仍看好黄金长期前景，预计未来两年内价格将再创新高。', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('36', 'finance', '科技', 'http://tech.sina.com.cn/', null, '', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('37', 'finance', '他想做出红外行业的“英特尔芯片”，用十年打造出一家上市公司', 'https://finance.sina.com.cn/tech/2024-12-02/doc-incxzkus9037305.shtml', null, '从文章内容来看，罗珏典领导下的国科天成（以下简称“国科”）是一家致力于红外高科技产品研发与生产的公司，成功上市并获得了投资者和业界的认可。以下是总结的关键点：\n\n1. **核心技术**：\n    - 国科专注于T2SL探测器的研发，这是II类超晶格材料制备及微纳加工技术的突破成果。\n    - T2SL探测器相比传统的MCT技术路线，在性能、产能、良率及成本方面具有优势。\n\n2. **战略定位和愿景**：\n    - 罗珏典希望国科成为国家高科技产业链中不可或缺的关键补充，而非多元化发展的公司。\n    ', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('38', 'finance', '这届黑五“又长又冷”，低价席卷跨境电商，商家困在比价系统里', 'https://finance.sina.com.cn/jjxw/2024-12-02/doc-incxzkuw5755205.shtml', null, '从这篇文章可以看出，跨境电商行业正在经历一个快速变化且竞争激烈的阶段。主要问题包括：\n\n1. **激烈的价格战**：由于行业内卷和新的经济周期，各大平台纷纷采取低价策略吸引消费者，导致商家利润空间不断被压缩。\n2. **比价系统带来的运营限制**：许多电商平台实施了比价机制，迫使卖家需要在不同平台上分别处理产品以避免竞争劣势，这增加了运营的复杂性和成本。\n3. **成本上升和收益下降**：除了直接的价格战外，包括运费、营销成本、售后罚款等在内的各种费用也在上升，进一步压缩利润空间。此外，由于经济环境的变化', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('39', 'finance', '昆明航空延误无赔偿', 'https://tousu.sina.com.cn/complaint/view/17378039680/?sld=089d2f3b0554ebe25db1897466d538d7', null, '您未提供具体的文章内容，因此我无法完成您的请求。请您提供需要提炼的具体文章内容。', '2024-12-03 21:24:23');
