INSERT INTO `news` VALUES ('54', 'ent', 'Evnia携手小蜜蜂战队E往无前，无所V惧', 'http://games.sina.com.cn/news/yw/2024-11-29/esports-incxtqvi5047754.shtml', null, '', '2024-12-03 21:24:23');
INSERT INTO `news` VALUES ('55', 'hot', '“对宪法法律始终保持敬畏之心”', 'https://news.sina.com.cn/zx/2024-12-04/doc-incyieum3729403.shtml', null, '12月4日为第十一个国家宪法日，宪法作为治国安邦的总章程，是党治国理政的根本法律依据及国家最高法律规范。习近平总书记强调要维护宪法权威和尊严，对宪法法律保持敬畏之心。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('56', 'hot', '作家琼瑶离世，遗体初步检验结果出炉', 'https://news.sina.com.cn/c/2024-12-04/doc-incyieuf0488221.shtml', null, '台湾知名作家琼瑶（本名陈喆）离世，终年86岁，其遗体送至台北怀爱馆检验后确认无他杀嫌疑，家属对死因无异议。琼瑶以言情小说闻名，多部作品被改编为电视剧和电影，在华人世界享有盛名。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('57', 'hot', '“非常戒严”夕令朝改 谁击垮了尹锡悦政府', 'https://k.sina.com.cn/article_1784473157_6a5ce645020032yw6.html?from=news&subch=onews', null, '韩国总统尹锡悦宣布“非常戒严”后被国会否决，显示出他在政治上的困境和决策失误。尽管他面临执政党在选举中的惨败和个人丑闻等不利因素，但他仍试图采取极端措施来巩固权力，结果却导致局势进一步恶化，众叛亲离。这反映了尹锡悦性格中固执己见的一面以及对“政治空气”的不敏感。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('58', 'hot', '现场视频：菲公务船恶意擦碰中国海警船', 'https://video.sina.com.cn/p/news/2024-12-04/detail-incyhyni0578266.d.html', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('59', 'hot', '美制裁130多家中国企业 波及范围有多大？', 'https://news.sina.com.cn/c/2024-12-04/doc-incyhynk7372564.shtml', null, '拜登政府在总统换届前针对中国半导体行业出台了新的限制政策，将140家公司（其中136家为中国公司）加入实体清单中。这些公司主要集中在半导体产业链上游的材料和设备企业。被列入实体清单后，相关公司将难以获得美国出口管理条例管辖物品的许可，但多家中国企业表示已提前布局供应链体系以应对可能的影响。中国商务部也对此表达了反对，并出台了针对美国半导体相关原材料的管制措施。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('60', 'hot', '最高检依法对李钺锋决定逮捕', 'https://news.sina.com.cn/c/2024-12-04/doc-incyhpwt3988110.shtml', null, '国家监察委员会调查终结并移送检察机关审查起诉的李钺锋（十四届全国人大原常委、台盟中央原常务副主席）涉嫌受贿案，最高人民检察院已依法对其作出逮捕决定，案件正进一步办理中。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('61', 'china', '外交部：中方奉劝菲方立即停止侵权挑衅', 'https://news.sina.com.cn/c/2024-12-05/doc-incyimai3676960.shtml', null, '外交部发言人林剑表示，针对菲律宾船只企图侵闯黄岩岛领海的行为，中国依法采取必要措施进行应对，强调黄岩岛为中国固有领土，并敦促菲律宾停止侵权挑衅行为。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('62', 'china', '春节申遗成功！我国世界非遗总数达44项', 'https://news.sina.com.cn/c/2024-12-04/doc-incyimac0396044.shtml', null, '我国申报的“春节——中国人庆祝传统新年的社会实践”在联合国教科文组织评审中通过，被列入人类非物质文化遗产代表作名录。至此，中国共有44个项目列入该组织的非物质文化遗产名录、名册，总数居全球首位。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('63', 'china', '检查结果互认致HIV感染者被拒诊，湖北卫健委回应', 'https://news.sina.com.cn/c/2024-12-04/doc-incyieuf0508679.shtml', null, '湖北武汉部分HIV阳性感染者因检验结果互认被拒诊，湖北省卫健委已通知所有定点医院屏蔽相关信息以保护隐私。此前，由于医疗机构间检查结果互认政策导致HIV检测结果公开，引发多名患者就医困难。专家呼吁在确保医疗信息共享的同时保护特殊疾病群体的隐私安全。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('64', 'china', '重庆市委书记和骑手交谈，询问订单数、月收入', 'https://news.sina.com.cn/c/2024-12-04/doc-incyimai3662466.shtml', null, '12月3日，重庆市委书记袁家军调研沙坪坝区“骑手友好街区”，该区创新建设了全国首个为外卖骑手提供便利的街区。袁家军强调要关心关爱包括外卖骑手在内的新就业群体，并指出社会结构变化要求提升社会工作水平。重庆已采取多项措施改善骑手等工作条件，累计建成5500多个“工会驿站”和1400多座“劳动者港湾”。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('65', 'china', '光速赢下比赛！孙颖莎女单比赛再获胜', 'https://news.sina.com.cn/c/2024-12-04/doc-incyieup0510347.shtml', null, '在2024年成都混合团体世界杯比赛中，中国乒乓球团队迎战德国队。第二盘女单比赛中，孙颖莎以3比0战胜德国选手索菲亚·克利。比赛继续进行中，为国乒加油。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('66', 'china', '菲律宾称中国海警船对菲方船只发射水炮，外交部回应', 'https://news.sina.com.cn/c/2024-12-04/doc-incyieuf0483030.shtml', null, '外交部发言人林剑表示，针对菲律宾称中国海警船对菲船只使用水炮一事，强调黄岩岛为中国固有领土，中国采取措施合法合理。呼吁菲律宾停止挑衅行为。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('67', 'china', '这座年轻城市，迎来“90后”市长候选人', 'https://news.sina.com.cn/c/2024-12-04/doc-incyieuf0517164.shtml', null, '青海省茫崖市举行了浙江援青医疗专家组的欢送仪式，市委书记刘为民和新任市长候选人苏铧烨出席了该活动。苏铧烨出生于1990年，毕业于清华大学法学院，在青海有丰富的基层工作经验，并将于近期担任县（市、区）党政正职职务。茫崖市是全国最年轻的城市之一，2022年地区生产总值首次突破百亿大关。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('68', 'china', '30秒回顾琼瑶的一生', 'https://news.sina.com.cn/2024-12-04/doc-incyhuet0692941.shtml', null, '台湾著名作家琼瑶于12月4日去世，享年86岁，在家中轻生身亡，警方排除外力介入。琼瑶本名陈喆，是中国当代著名作家、编剧和影视制作人，代表作品有《窗外》、《一帘幽梦》、《梅花烙》和电视剧《还珠格格》等。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('69', 'china', '黄晓明发博悼念琼瑶', 'https://news.sina.com.cn/2024-12-04/doc-incyhuet0695390.shtml', null, '知名作家琼瑶4日在家中轻生去世，享年86岁。黄晓明发博悼念，回忆与琼瑶合作经历，赞扬其作品对几代人的影响，并表示会珍惜她留下的精神财富。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('70', 'china', '钟薛高设备将二次拍卖，创始人：卖红薯还债', 'https://news.sina.com.cn/c/2024-12-04/doc-incyhuer3903941.shtml', null, '钟茂（上海）食品科技有限公司因与必斐艾食品有限公司的合同纠纷，其203件设备在首次拍卖流拍后将于12月10日进行二次拍卖，起拍价降至约444.96万元。此外，钟茂公司及其母公司钟薛高公司涉及多起法律诉讼案件，被执行总金额达1507.59万元，钟薛高公司还被列入失信被执行人名单。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('71', 'china', '黄奕：有幸这一生和琼瑶在红尘作伴，活得潇潇洒洒', 'https://news.sina.com.cn/c/2024-12-04/doc-incyhuet0675261.shtml', null, '知名作家琼瑶于2024年12月4日下午在新北市淡水区家中轻生身亡，享寿86岁。演员黄奕发文悼念，回忆了琼瑶对她职业生涯和个人生活的深远影响，并表达了深切的怀念之情。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('72', 'china', '多位演员发博悼念琼瑶', 'https://news.sina.com.cn/2024-12-04/doc-incyhuer3907596.shtml', null, '知名作家琼瑶于12月4日去世，享年86岁。多位演员如苏有朋、林心如等发文悼念，感谢她对他们的影响和贡献，表达了对其离去的深切哀悼与怀念之情。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('73', 'china', '琼瑶生平作品', 'https://news.sina.com.cn/c/2024-12-04/doc-incyhuet0654559.shtml', null, '知名作家琼瑶于今日去世，享年86岁。她以言情小说著称，代表作包括《窗外》、《烟雨濛濛》等，并改编多部电视剧如《还珠格格》和《情深深雨濛濛》，对中国影视界影响深远。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('74', 'world', '德国总理：向乌克兰派兵“绝无可能”', 'https://news.sina.com.cn/w/2024-12-04/doc-incyimam0450437.shtml', null, '德国总理朔尔茨明确表示现阶段德国不会向乌克兰派兵，并强调国防部长和外交部长对此持相同意见。此前，德国外长贝尔伯克的言论被解读为可能支持派兵，但朔尔茨重申了德国政府的一致立场。\n\n此内容已压缩至100字以内。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('75', 'world', '乌克兰突然宣布：停止！', 'https://news.sina.com.cn/w/2024-12-05/doc-incyimai3673394.shtml', null, '乌克兰能源部副部长罗曼·安达拉克宣布，自2025年1月起，乌克兰将停止俄罗斯天然气过境运输。尽管如此，乌方将继续通过“友谊”管道向欧洲输送俄石油至2030年。同时，乌克兰与欧盟签署协议，利用冻结的俄罗斯资产吸引高达350亿欧元援助。此外，俄乌双方继续在前线交战，局势依然紧张。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('76', 'world', '韩国总统尹锡悦将于当地时间周四发表讲话', 'https://news.sina.com.cn/w/2024-12-04/doc-incyimac0402427.shtml', null, '韩国总统尹锡悦原定当地时间周四发表讲话。此前，12月3日尹锡悦宣布紧急戒严令以维护“自由宪政秩序”，但在4日凌晨韩国国会通过决议案要求解除戒严令后，该措施无效并被迅速解除。随后，总统府部分高级幕僚辞职，多个在野党提出对尹锡悦的弹劾动议案。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('77', 'world', '美股三大指数集体高开 赛富时涨超10%', 'https://news.sina.com.cn/w/2024-12-04/doc-incyimai3653950.shtml', null, '美股三大指数高开，纳指涨0.55%，道指涨0.53%，标普500指数涨0.31%。赛富时和迈威尔科技因业绩超预期分别大涨超10%和16%；NexGen Energy涨超4%，赢得美国核电公司首批铀供应合同。中金科工业和高途跌幅均超过13%，后者第三季度经营亏损达4.9亿元，毛利率下降。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('78', 'world', '美国医疗保健巨头联合健康CEO在纽约被枪杀', 'https://news.sina.com.cn/w/2024-12-04/doc-incyimac0404486.shtml', null, '美国医疗保健巨头联合健康的首席执行官布莱恩·汤普森在纽约市中心遭有针对性的袭击，胸部中弹后被送往医院抢救无效死亡。汤普森现年50岁，2004年加入公司，曾担任多个领导职位。（100字）', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('79', 'world', '伊拉克恢复往返黎巴嫩直航航班', 'https://news.sina.com.cn/w/2024-12-04/doc-incyieup0546093.shtml', null, '伊拉克交通部12月4日宣布，伊拉克航空已恢复巴格达国际机场与贝鲁特之间的直飞航线。此前，因黎巴嫩安全局势恶化，该航线自9月27日起暂停运营。这条路线的复航标志着两国间航班服务恢复正常。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('80', 'world', '格鲁吉亚警方逮捕反对党领导人', 'https://news.sina.com.cn/w/2024-12-04/doc-incyieum3765693.shtml', null, '格鲁吉亚警方于12月4日搜查了多个反对党和组织的办公室，并在行动后逮捕了反对党阿哈利党的领导人格瓦拉米亚。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('81', 'world', '以色列代表团将前往埃及 就加沙停火等问题谈判', 'https://news.sina.com.cn/o/2024-12-04/doc-incyieum3760241.shtml', null, '由以色列国家安全局局长罗南·巴尔率领的代表团将于12月5日抵达埃及开罗，就潜在的加沙停火和被扣押人员交换协议进行谈判。代表团中包括一名总理内塔尼亚胡的“特使”。目前，以色列政府尚未对此消息作出回应。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('82', 'world', '只说支持避谈邀约 这场北约会议又让乌克兰失望了', 'https://news.sina.com.cn/w/2024-12-04/doc-incyieum3752434.shtml', null, '北约外长会议在布鲁塞尔召开，重点讨论了对乌克兰的支持和军事援助问题。尽管乌克兰寻求加入北约的正式成员身份，但目前北约成员国尚未就该议题达成共识。此外，会议还将关注北极地区和“南部邻国”事务。专家指出，作为军事联盟，北约介入这些地区的行动可能加剧危机与动荡。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('83', 'world', '政治对立凸显 韩国再次进入弹劾现任总统时间', 'https://news.sina.com.cn/w/2024-12-04/doc-incyhynk7378024.shtml', null, '韩国六个在野党联合向国会提交了针对总统尹锡悦的弹劾动议案，指控其紧急戒严令违宪违法。根据程序，若获得至少200张赞成票，则弹劾案将在国会通过，并送交宪法法院裁决。最终结果将决定尹锡悦是否遭罢免或恢复职权。这一事件凸显了韩国政治对立和朝野斗争的加剧。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('84', 'world', '韩国民众举行大规模集会 要求尹锡悦下台', 'https://news.sina.com.cn/w/2024-12-04/doc-incyhyni0595000.shtml', null, '12月4日，韩国多个市民团体在首尔光化门等地举行集会，要求总统尹锡悦下台。这是韩国民众8年来首次大规模烛光集会要求总统辞职。3日晚，尹锡悦宣布紧急戒严令，4日凌晨即解除。随后，多个在野党发起针对尹锡悦的弹劾动议案。此次事件凸显韩国政治严重对立。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('85', 'finance', '何立峰会见美国高盛集团总裁温泽恩时指出 中国欢迎美资企业深化对华合作', 'https://finance.sina.com.cn/china/2024-12-04/doc-incyieup0544714.shtml', null, '何立峰会见美国高盛集团总裁温泽恩时指出，中国欢迎美资企业深化对华合作，推进中美关系健康发展。何立峰表示，中国正全面深化改革和扩大开放，鼓励更多美资金融机构及长期资本深化与中国的互利合作。温泽恩表示，高盛对未来中国经济充满信心，并愿意继续扩大合作以促进中美经贸关系。（103字）', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('86', 'finance', '关键时刻，美联储释放重磅信号：可能暂停降息', 'https://finance.sina.com.cn/stock/zqgd/2024-12-04/doc-incyimai3657009.shtml', null, '关键内容提取如下：\n\n美联储官员暗示或于12月暂停降息以评估经济状况；欧洲央行则可能继续宽松政策并将于下周降息。OECD警告全球经济面临多重下行风险，并建议发达国家延续宽松货币政策来应对这些挑战。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('87', 'finance', '王磊被查一个多月后，阿斯利康任命中国区业务新负责人', 'https://finance.sina.com.cn/jjxw/2024-12-04/doc-incyimai3659957.shtml', null, '阿斯利康宣布Iskra Reic接替王磊担任全球执行副总裁及国际业务负责人，负责包括中国在内的多个地区战略。王磊因在中国接受调查暂离岗位。Iskra拥有丰富的国际经验和领导经历，阿斯利康CEO对其评价颇高，认为其能推动公司向前发展。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('88', 'finance', '春节申遗成功！我国世界非遗总数达44项', 'https://finance.sina.com.cn/jjxw/2024-12-04/doc-incyimai3651299.shtml', null, '中国申报的“春节——中国人庆祝传统新年的社会实践”被列入联合国教科文组织人类非物质文化遗产代表作名录。至此，中国共有44个项目列入该组织的非遗名录、名册，总数居全球首位。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('89', 'finance', '12月4日上市公司减持汇总：开普检测等9股拟减持（表）', 'https://finance.sina.com.cn/stock/relnews/cn/2024-12-04/doc-incyieuh7294431.shtml', null, '12月4日盘后，共有9家A股上市公司包括开普检测、海创药业等宣布了拟减持计划。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('90', 'finance', '科技', 'http://tech.sina.com.cn/', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('91', 'finance', '中国科学家推出新健康评估体系：重点关注“离健康还有多远”', 'https://cj.sina.cn/article/norm_detail?url=https%3A%2F%2Ffinance.sina.com.cn%2Fjjxw%2F2024-12-04%2Fdoc-incyfwzc0984097.shtml', null, '中国科学家推出新的健康评估体系——“健康状况图谱”（HSM），这是一种结合空腹和餐后代谢数据的二维框架，能够更全面地反映个体的代谢健康状态。相比于传统基于空腹数据的方法，该模型通过“健康表型状态评分”和“弹性稳态评分”，能提供更丰富的信息，有助于早期发现器官功能障碍及实施精准预防与治疗策略。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('92', 'finance', '腾讯内部人士称破晓项目解散不实，有员工内部寻找其他岗位', 'https://finance.sina.com.cn/roll/2024-12-04/doc-incyhchz0868350.shtml', null, '《星之破晓》项目并未解散，但将进行调整并暂停先遣测试服，原计划的200多名员工可选择内部转岗。游戏于今年5月上线不删档先遣服，是王者荣耀IP首款英雄动作手游，预计正式推出时间为2025年1月。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('93', 'finance', '天猫超市无理由拒退款', 'https://tousu.sina.com.cn/complaint/view/17378069978/?sld=36e3a35d5969a16dc1edcb03765438d1', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('94', 'finance', '乘东风 朝阳港蝶变“赛点”已来\r\n', 'http://bj.leju.com/', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('95', 'finance', '2025“国考”笔试结束 试题有何新变化？', 'https://edu.sina.com.cn/', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('96', 'ent', '琼瑶 翩然而去', 'http://k.sina.com.cn/article_1652484947_627eeb5302001n18e.html', null, '琼瑶的遗书揭示了她对死亡的看法和她的生命哲学。在这封信中，她表达了对她所爱的人们的深切情感，并传达了一个明确的信息：她选择以一种优雅的方式离开这个世界。\n\n1. **尊重自主权**：\n   琼瑶非常重视生命的自主性，在面对衰老和疾病时，她希望能够保持尊严并主动地决定自己的命运。这种态度体现了对个人生命权利的深刻理解与尊重。\n\n2. **珍惜生活中的美好瞬间**：\n   她提醒大家要勇敢地活着，并珍惜那些“能爱、能恨、能笑、能哭”的时刻。这些美好的经历构成了生命的本质，也让她在回顾一生时感到无憾和满足。\n\n', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('97', 'ent', '向黑夜和忙碌了一天的自己说声晚安', 'http://k.sina.com.cn/article_2011075080_77de920804001hqg6.html', null, '原文主要是个人的一句晚安感言，并无具体事件或详细信息可供提取关键内容。原文附带的声明强调了文章内容仅代表作者个人观点，以及关于版权等问题的联系方式说明。因此，难以提炼出符合要求的关键内容摘要。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('98', 'ent', '申遗成功！春节是刻在中国人骨子里的仪式感', 'http://video.sina.com.cn/p/finance/2024-12-04/detail-incyimam0451473.d.html', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('99', 'ent', '晚安，深圳', 'http://k.sina.com.cn/article_6321540324_m178cb0ce4033017bpw.html', null, '该段文字主要是表达了对深圳市民的一句晚安祝福，并未包含具体的信息或事件内容。核心在于传递一种温馨的夜晚问候和结束一天生活的美好祝愿。文中也包括了版权声明，提醒读者关于内容、版权等问题的联系方式。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('100', 'ent', '路过人间，也才几十年，却为了爱，勇于蹉跎岁月', 'http://k.sina.com.cn/article_2024623547_m78ad4dbb03301g11c.html', null, '歌手郁可唯演唱的歌曲《路过人间》温暖治愈，歌词表达了即使人生短暂，也要为了爱勇敢付出的情感。鼓励人们在人生的相聚别离中勇敢表达爱意，珍惜每一个瞬间。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('101', 'ent', '英超-萨拉赫点射加克波破门 利物浦2-0曼城', 'https://sports.sina.com.cn/g/pl/2024-12-02/doc-incxzkus9038399.shtml', null, '12月2日，英超第13轮比赛中，利物浦主场以2-0战胜曼城。比赛关键进球包括加克波在第13分钟的抢点破门和萨拉赫在第78分钟罚中的点球。利物浦首发阵容有凯莱赫、乔-戈麦斯等球员，而曼城则由奥尔特加领衔出战。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('102', 'ent', '英超-拉什福德齐尔克泽双响 曼联4-0埃弗顿', 'https://sports.sina.com.cn/g/pl/2024-12-02/doc-incxzkuu8982059.shtml', null, '12月1日，英超第13轮比赛中，曼联在主场以4-0战胜埃弗顿。比赛中，拉什福德和齐尔克泽分别梅开二度，B费贡献两次助攻。曼联首发包括奥纳纳、德里赫特等球员；埃弗顿则由皮克福德领衔。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('103', 'ent', '英超-帕尔默传射杰克逊破门 切尔西3-0维拉', 'https://sports.sina.com.cn/g/pl/2024-12-02/doc-incxzkus9041094.shtml', null, '在英超第13轮比赛中，切尔西主场以3-0战胜阿斯顿维拉。比赛的关键进球分别由杰克逊（8分钟）、恩佐（37分钟）和帕尔默（85分钟）完成。切尔西的首发阵容包括罗伯特-桑切斯、库库雷利亚等球员；阿斯顿维拉方面，首发有马丁内斯等人，并在下半场进行了人员调整。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('104', 'ent', '西甲-贝林厄姆破门姆巴佩建功 皇马2-0赫塔菲', 'https://sports.sina.com.cn/g/laliga/2024-12-02/doc-incxzkur2261938.shtml', null, '西甲第15轮，皇马在主场以2-0战胜赫塔菲。比赛中，贝林厄姆于第30分钟罚中点球，姆巴佩则在第38分钟通过禁区外远射再下一城。此役，库尔图瓦担任门将首发，其他关键球员包括贝林厄姆、巴尔韦德和姆巴佩等。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('105', 'ent', '浓眉33+11詹姆斯27+14 湖人险胜爵士回西部第5', 'https://sports.sina.com.cn/basketball/nba/2024-12-02/doc-incxzvkn8862405.shtml', null, '北京时间12月2日，NBA常规赛中，湖人以105-104险胜爵士。此役后，湖人的战绩为12胜8负，排名升至西部第五；而遭遇四连败的爵士则跌至西部倒数第二（4胜16负）。比赛中，浓眉拿下33分11篮板，詹姆斯贡献27分5篮板14助攻。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('106', 'ent', '双色球预测-贾利江中二等揽180万', 'https://lottery.sina.com.cn/number/?from=xw', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('107', 'ent', 'kassad：ESIC最糟糕的一点就是管理它的人', 'http://games.sina.com.cn/news/yw/2024-12-04/esports-incyhuet0691556.shtml', null, '您未提供具体的文章内容，因此我无法进行摘要。如果您能提供文章的具体文本，我很乐意帮助您提取关键内容并制作摘要。', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('108', 'ent', '技嘉助力电竞上海大师，为中国电竞保驾护航！', 'http://games.sina.com.cn/news/yw/2024-12-04/esports-incyhuer3911650.shtml', null, '', '2024-12-05 00:13:43');
INSERT INTO `news` VALUES ('109', 'hot', '习近平出席中拉论坛第四届部长级会议开幕式并发表主旨讲话', 'https://news.sina.com.cn/c/xl/2025-05-13/doc-inewmtfr0013454.shtml', null, '国家主席习近平出席中国-拉美和加勒比国家共同体论坛第四届部长级会议开幕式，发表主旨讲话《谱写构建中拉命运共同体新篇章》。他宣布中方将同拉方携手启动五大工程，包括团结、发展、文明、和平和民心工程，以共谋发展振兴，共建中拉命运共同体。讲话强调无论国际形势如何变化，中国始终是拉美国家的好朋友、好伙伴。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('110', 'hot', '同巴西总统卢拉会谈', 'https://news.sina.com.cn/c/xl/2025-05-13/doc-inewmtfp4126094.shtml', null, '国家主席习近平与巴西总统卢拉会谈，双方宣布将两国关系提升为中巴命运共同体，深化多领域合作，包括基础设施、农业、能源及新兴领域。强调人文交流与多边协作，维护全球南方国家利益，反对单边主义。两国签署20份合作文件，并就乌克兰危机交换意见，同意加强沟通协调，共同维护国际公平正义。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('111', 'hot', '中美谈判 三大看点', 'https://k.sina.com.cn/article_1784473157_6a5ce645027037bj0.html?from=news&subch=onews', null, '中美经贸会谈取得实质性进展，双方大幅降低关税，取消91%的关税，争议领域暂停实施24%关税。此次会谈务实高效，体现对等原则，选址中立国日内瓦。专家指出，结果打破“中美经济可切割”谬论，展现理性认知。双方同意建立机制继续协商，为未来谈判奠定基础。中国应保持战略定力，维护发展利益。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('112', 'hot', '李在明妻子因公款吃喝被判罚150万韩元', 'https://k.sina.com.cn/article_6105713761_16bedcc6102001n85u.html?from=news&subch=onews', null, '韩国第21届总统大选候选人登记完成，李在明等7人参与竞选。民调显示李在明支持率领先。他身着防弹衣参加拉票活动。其妻金惠景因违反《公职选举法》被判处罚金。李在明涉嫌违法一案仍在审理中，此前判决结果不一，最高法院发回重审。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('113', 'hot', '这轮中美关税会谈让台湾社会看清了什么？', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmtfs6803422.shtml', null, '中美经贸会谈后发布联合声明，大幅降低双边关税，美国作出让步。岛内舆论对此反响强烈，台湾社会赞赏大陆以实力赢得尊重，展现担当和格局。同时，赖清德“舔美”行为遭批评，其“脱中入北”被指不切实际。此次会谈使台湾民众更认清，大陆是最可依靠的力量，“台独”害台，美国不可靠。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('114', 'hot', '2025年底全国行政村5G通达率将超过90%', 'https://k.sina.com.cn/article_5044281310_12ca99fde02002d0ty.html?from=news&subch=onews', null, '中央网信办等四部门印发《2025年数字乡村发展工作要点》，明确到2025年底，数字乡村发展“十四五”圆满收官。重点任务包括夯实基础设施、支撑粮食安全与防返贫、发展智慧农业、壮大新业态、繁荣数字文化、提升治理效能、深化普惠服务、建设智慧美丽乡村及统筹推进整体发展，推动城乡融合发展与乡村振兴。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('115', 'hot', '中东“油王”沙特阿美削减100亿美元股息', 'https://news.sina.com.cn/o/2025-05-13/doc-inewmhrv0228017.shtml', null, '沙特阿美一季度净利润同比下降4.6%，股息总额大幅下滑至213.6亿美元，远低于上年同期的310亿美元。国际油价承压，主要受OPEC+增产及贸易风险影响。作为沙特政府财政核心支柱，沙特阿美派息减少将加剧政府财政压力，可能影响其经济现代化计划。尽管如此，公司仍计划加大资本开支，推动下游和新能源业务增长。', '2025-05-14 03:10:29');
INSERT INTO `news` VALUES ('116', 'china', '北京白天气温超30℃，为何晚上却下冰雹？', 'https://news.sina.com.cn/o/2025-05-13/doc-inewmtfr0008288.shtml', null, '北京今夜出现雷雨和强对流天气，房山、门头沟、朝阳等区伴有冰雹，部分如鸡蛋大小。强回波向东南移动，影响丰台、大兴、通州等地。气象台发布雷电黄色、大风蓝色和冰雹黄色预警，提醒市民防雹防雷，妥善安置室外物品。白天高温为冰雹形成提供条件，需关注短时预警并做好防护。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('117', 'china', '直径超4厘米！北京多地下冰雹，满地都是“鸽子蛋”', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmtfu1771123.shtml', null, '\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('118', 'china', '注意！北京局地可能造成雹灾', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmnxu6907034.shtml', null, '北京部分地区出现强对流天气，房山、门头沟、朝阳、丰台、海淀等地有雷阵雨伴冰雹，可能造成雹灾。强回波向东南移动，影响丰台、大兴、通州及中心城区。北京已发布雷电黄色、大风蓝色和冰雹黄色预警，出行请注意防雹、防雷电，确保安全。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('119', 'china', '中央纪委书记会见了一位“老朋友”', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmnxw1880319.shtml', null, '文章关键内容：2024年5月，中共中央政治局常委李希会见古巴外长罗德里格斯，强调中古建交65周年背景下，双方将深化政治互信、战略协作及特殊友好关系。罗德里格斯感谢中国支持古巴发展，重申一个中国原则。此次会面围绕中拉论坛第四届部长级会议展开，中方持续反对美国对古巴的封锁制裁，支持古巴经济社会发展。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('120', 'china', '中美关税大幅调降，会否波及债券牛市？', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmhry1984885.shtml', null, '2025年2月至4月，外资大幅增持中国债券，其中2-3月净增持269亿美元，同比增长84%，4月前18天净买入332亿美元。受贸易摩擦影响，资金避险情绪推动债市走牛，10年期国债收益率显著下行。然而，中美达成关税共识后，市场风险偏好回升，债市回调，股市反弹。分析认为，未来关税谈判进展将成债市关键变量，股债跷跷板效应明显。央行全面降准降息政策落地，或致债市利好出尽。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('121', 'china', '被政治骗子利用的“老虎”王宜林，受贿数额特别巨大', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmhrt4294344.shtml', null, '2025年5月13日，内蒙古鄂尔多斯市中级人民法院一审宣判中石油原董事长王宜林受贿案，判处其有期徒刑十三年，并处罚金三百万元。经查明，1996年至2020年间，王宜林利用职务便利为他人谋利，非法收受财物折合人民币3501万余元。鉴于其如实供述罪行、积极退赃，依法从轻处罚。王宜林被指丧失理想信念，严重违纪违法，构成受贿犯罪。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('122', 'china', '特朗普突然提到“统一”，台当局急了', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmhrw6983995.shtml', null, '特朗普在白宫记者会上称中美贸易谈判成果将有利于“统一与和平”，引发外界对台海问题的猜测。台湾当局否认谈判涉及台湾议题，美国国务院也表示特朗普言论针对美中贸易关系，对台政策未变。此事件反映出台湾方面的焦虑。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('123', 'china', '中石油原董事长王宜林一审获刑十三年', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmhry1955880.shtml', null, '2025年5月13日，内蒙古鄂尔多斯市中级人民法院一审宣判中石油原董事长王宜林受贿案。王宜林因利用职务便利为他人谋利，非法收受财物折合人民币3501万余元，被判有期徒刑十三年，并处罚金300万元。鉴于其如实供述罪行、积极退赃，依法从轻处罚。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('124', 'china', '中央巡视组进驻后，郭卫新被查', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmaka2045867.shtml', null, '内蒙古自治区包头市人大常委会原副主任郭卫新涉嫌严重违纪违法，正接受纪律审查和监察调查。郭卫新曾任职纪检监察系统，后担任包头市多项重要职务。今年，内蒙古自治区政协原副主席王中和也被查，中央第十巡视组于4月进驻内蒙古开展巡视工作。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('125', 'china', '8个中央指导组进驻，有何深意', 'https://news.sina.com.cn/c/2025-05-13/doc-inewmaiv4345225.shtml', null, '8个中央指导组已完成对21个地方和单位的进驻，组长均由正省部级干部担任。此次学习教育旨在深入贯彻中央八项规定精神，聚焦违规吃喝、收送礼金等问题，强调问题导向和精准督导。选择指导对象具有代表性，涉及部委、央企及高校等领域，意在通过“解剖麻雀”推动全党整改。专家指出，中央八项规定精神的学习教育体现了党对作风建设的长期坚持，旨在从根本上铲除腐败滋生土壤，强化党群联系，确保从严管党治党的长效性。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('126', 'china', '小米“至暗时刻”还没过去', 'https://news.sina.com.cn/c/2025-05-13/doc-inewkwaa7140219.shtml', null, '小米汽车因多起事件遭遇舆论危机，包括SU7智驾事故、马力限制及碳纤维前舱盖虚假宣传等，导致品牌形象受损和4月交付量下降。尽管小米汽车凭借单一车型跻身新势力第一梯队，但流量双刃剑效应明显，安全与诚信问题亟待解决。未来，小米需平衡营销与技术实力，重建用户信任以实现长远发展。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('127', 'china', '享受红土！郑钦文第七次“翻山”之旅能否成功', 'https://news.sina.com.cn/c/2025-05-13/doc-inewkvzx4444331.shtml', null, '郑钦文在2025年WTA1000罗马站中击败前美网冠军安德莱斯库，连续三年闯入八强。比赛中，郑钦文虽发球状态不佳，但凭借多变战术和强大心态逆转取胜，展现出成长与韧性。接下来，她将第七次挑战现任世界第一萨巴伦卡，红土赛季表现值得期待。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('128', 'china', '“健康证”办理存在违规问题 沈阳市卫健委通报', 'https://news.sina.com.cn/c/2025-05-13/doc-inewkwaa7154991.shtml', null, '沈阳市卫健委通报了关于健康证办理问题的调查处理情况。沈阳康民医院和辽宁省健康产业集团华晨医院被发现存在未经医师亲自诊查出具健康证明的违规行为，后者还违反了医疗质量安全核心制度。辖区卫生健康部门已责令这两家医院停止从业人员健康检查工作，并依法立案查处，将对机构和个人作出行政处罚。此事件揭示了健康证办理过程中的乱象及公共安全存在的隐患。', '2025-05-14 03:13:40');
INSERT INTO `news` VALUES ('129', 'mil', '感悟回信｜一直追太阳，他们以青春之名逐梦高原', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewmhrw6977052.shtml', null, '文章讲述了青年在西藏贡献青春力量的故事。高宁宁援藏支教，用音乐促进民族团结；杨聪戍边十一载，心系百姓，被誉为“洋葱警长”；山西师范大学研究生支教团扎根墨脱九年，助力西部教育。他们响应国家号召，将青春融入党和人民事业，为西藏发展贡献力量。习总书记勉励青年到祖国需要的地方发光发热，青年们以实际行动回应期望，推动西部大开发与中国式现代化建设。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('130', 'mil', '青年探访丨浙江德清：环保“长”在寻常日子里', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewmhrt4307551.shtml', null, '文章介绍了浙江德清将环保融入日常生活的多种方式，如牙膏包装更换、自动驾驶汽车、咖啡“闭环”等，展现了“两山”理念在当地的具体实践。通过青山绿水的生态环境，体现了人与自然和谐共生的美好景象。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('131', 'mil', '【跨区协奏 双核共振】1+1>2 昆明寻甸东川组“跨区搭档”', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewmhrt4283719.shtml', null, '昆明市通过天生桥园区探索跨区域产业协调发展，该园区由东川区和寻甸县共建，尽管“籍贯”在寻甸，但由东川运营。针对土地资源限制和审批难题，两区县深化合作机制，明确权责、规划、利益分成及问题解决机制。目前园区入驻企业48家，2024年规上工业产值达13.42亿元。未来将加大招商协同，优化产业链布局，打造跨区域产业协作样板区。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('132', 'mil', '空地联动 科技赋能——吉林交警精心打造“无人机+”警务模式记事', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewkruc0472319.shtml', null, '吉林交警部门通过“无人机+”警务模式提升交通管理效能。高速公路长春、四平支队试点无人机巡逻，实现空中巡防、疏堵保畅、事故快处等功能，提升路面见警率和管事率。“五一”期间，无人机助力景区交通管理，空地联动保障道路畅通与安全。同时，无人机在车辆故障救援、护学模式中发挥重要作用，构建多维度立体化安全防护体系，获群众好评。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('133', 'mil', '内蒙古煤炭工业发展“十五五”规划启动编制', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewmnxw1873502.shtml', null, '内蒙古自治区煤炭工业发展“十五五”规划完成政府采购，将进入编制阶段。作为国家重要能源基地，内蒙古将遵循“四个革命、一个合作”战略，坚持生态优先、绿色发展，保障煤炭供应，推动清洁高效利用，促进煤炭产业智能化、绿色化、高效化转型，引领行业高质量发展。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('134', 'mil', '2025年高招工作具体方案公布', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewmtfr0021998.shtml', null, '安徽省2025年高考实行“3+1+2”模式，总分750分，包括语文、数学、外语各150分，选考科目各100分。选考科目中历史和物理以原始分计入，其他科目以等级分计入。招生类别分为普通类、艺术类、体育类，志愿填报采用“院校专业组”方式。录取工作于7月初开始，8月中旬结束。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('135', 'mil', '河南“烤”验持续 各地多举措抗旱防高温', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewkruc0472784.shtml', null, '河南多地通过科技赋能和统筹联动，积极应对干热风对小麦灌浆期的影响。安阳推广科学灌溉与叶面喷施技术，南阳创新灌溉模式并投入大量资金抗旱，新乡构建防控网络并强化技术指导。各地采取“一喷三防”、病虫害防治等措施，确保小麦丰产丰收。当前，河南小麦进入关键灌浆期，全省上下全力织密夏粮丰收“防护网”。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('136', 'mil', '用好科技创新关键变量 银川以\"智改数转\"重塑产业基因', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewkvzz0363560.shtml', null, '银川市通过科技创新推动高质量发展，高端装备制造和数字智能制造成为亮点。共享铸钢的3D打印技术、北瓷新材料的氮化铝陶瓷、威力传动的大兆瓦风电齿轮箱等产品打破国外垄断，市场占有率领先。银川一季度规上工业增加值增长9%，高技术制造业增长19.1%。全市聚焦创新体系重构，申报科技项目1071项，总研发投入18.8亿元，以“智改数转”重塑产业基因。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('137', 'mil', '央广财评|有理、有利、有节！世贸组织欢迎中美经贸高层会谈取得积极成果', 'https://news.sina.com.cn/zx/gj/2025-05-12/doc-inewicst5251974.shtml', null, '中美日内瓦经贸会谈取得实质性进展，双方取消91%加征关税并暂停24%反制关税，标志着通过平等对话解决分歧的重要一步。世贸组织总干事伊维拉对此表示欢迎，称这一进展对全球至关重要。中美经贸合作本质是互利共赢，维护健康稳定的双边关系符合两国及全球利益，有助于促进自由贸易和多边主义发展。（宓迪）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('138', 'mil', '国际博物馆日将至，北京多家博物馆将“扎堆”焕新', 'https://news.sina.com.cn/zx/gj/2025-05-13/doc-inewkrue7247565.shtml', null, '国际博物馆日来临，北京多家博物馆焕新开放或推出重磅展览。北京大葆台遗址博物馆将于2025年全新亮相，展示汉代文明；通州区博物馆增设互动体验项目，推出“左辅雄藩”主题展。此外，中国铁道博物馆、首都博物馆、北京艺术博物馆等也将推出特色展览，涵盖铁路电影、南洋文化、殷商文物及明清禽鸟主题，丰富公众文化体验。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('139', 'world', '特朗普：美国务卿鲁比奥将前往土耳其参加俄乌会谈', 'https://news.sina.com.cn/w/2025-05-14/doc-inewmxpn9929060.shtml', null, '特朗普称本周晚些时候俄乌将土耳其举行会谈，美国人员也将前往，此消息来源于财联社，由特朗普在沙特-美国投资论坛上透露。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('140', 'world', '美媒：美平均关税税率仍为1934年来最高', 'https://news.sina.com.cn/w/2025-05-13/doc-inewmxps1680409.shtml', null, '中美经贸会谈取得进展，市场反应积极。但美国媒体CNBC报道，美国对多国加征关税，致平均关税税率升至17.8%，为1934年以来最高水平。（CCTV国际时讯）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('141', 'world', '印度宣布一名巴基斯坦外交官为不受欢迎的人', 'https://news.sina.com.cn/w/2025-05-13/doc-inewmxpq6682141.shtml', null, '印度外交部宣布一名巴基斯坦官员为不受欢迎的人，因其从事与官方身份不符的活动。该官员被要求24小时内离开印度。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('142', 'world', '俄副外长：俄美两国将举行双边谈判', 'https://news.sina.com.cn/w/2025-05-13/doc-inewmtfs6800503.shtml', null, '俄罗斯副外长里亚布科夫宣布，俄美将举行双边谈判，但未确定具体日期。此外，关于俄乌直接谈判，特朗普的参与意愿取决于普京。俄方强调，将在不损害伙伴关系前提下发展对美关系，同时批评欧洲试图阻止俄美关系正常化。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('143', 'world', '乌方称普京出席泽连斯基才会参加会谈，俄方最新回应', 'https://news.sina.com.cn/w/2025-05-13/doc-inewmnxw1891943.shtml', null, '乌克兰总统泽连斯基的高级助手表示，泽连斯基仅在普京出席的情况下参加土耳其谈判。波多利亚克称，只有普京能决定战争走向。普京提议俄乌直接对话，俄方正准备伊斯坦布尔谈判。俄乌在停火与谈判顺序上存分歧，西方被指借停火助乌恢复军力。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('144', 'world', '乌方：泽连斯基只接受与普京会谈 拒见其他俄代表', 'https://news.sina.com.cn/w/2025-05-13/doc-inewmaiy7070996.shtml', null, '乌克兰总统泽连斯基表示愿与俄罗斯总统普京在土耳其直接会谈，不会会见其他俄罗斯代表。埃尔多安支持此次会晤，普京也同意在无先决条件下进行直接谈判，提议5月15日于伊斯坦布尔恢复谈判。特朗普表示支持此次会晤。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('145', 'world', '印度拟采取反制举措 对美国部分输印商品征收关税', 'https://news.sina.com.cn/w/2025-05-13/doc-inewkwaa7133818.shtml', null, '印度拟对美出口产品征税反击美国钢铝关税，同时印美正推进贸易谈判，计划2025年前达成多部门双边贸易协定。双方讨论了关税与非关税壁垒问题，目标通过“提早共赢”机会实现互利。印度或成首个与美签署贸易协议的国家，谈判旨在避免美国总统提出的对等关税影响。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('146', 'world', '莫迪称印度的行动震惊巴基斯坦', 'https://news.sina.com.cn/w/2025-05-13/doc-inewkruc0441584.shtml', null, '印度总理莫迪12日发表全国讲话，称印度将对任何恐怖袭击作出强烈回应，并透露5月6日印度军队对巴基斯坦境内“恐怖基础设施”进行了打击，令巴方震惊。莫迪还表示，巴方军事作战指挥官于5月10日与印度国防部长接触，双方仅讨论停火问题。这是印度发起“朱砂行动”后莫迪的首次讲话。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('147', 'world', '杜特尔特在狱中赢得市长选举', 'https://news.sina.com.cn/w/2025-05-13/doc-inewkmnh7291300.shtml', null, '菲律宾前总统杜特尔特在荷兰海牙监狱中以压倒性优势（8倍于对手票数）赢得达沃市市长选举。他曾于1988年首次当选该市市长。今年3月，他因“禁毒战争”被国际刑事法院逮捕。其女、菲律宾副总统莎拉表示将商讨杜特尔特宣誓就职及履职事宜。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('148', 'world', '特朗普“宏大减税法案”公布：十年拟减税4万亿', 'https://news.sina.com.cn/w/2025-05-13/doc-inewkmnc4598599.shtml', null, '美国众议院公布税收法案，计划十年内减税超4万亿美元并削减1.5万亿支出，延续特朗普时期的减税政策。草案包括免除小费与加班收入个税，但未解决州税和地方税抵扣争议。特朗普拟用关税收入为中低收入者减税，但经济学家认为此计划缺乏可行性，因关税收入不足以替代所得税，且可能引发经济衰退。此外，特朗普呼吁永久延长2017年减税法案，未来十年成本或达5至11.2万亿美元，具体筹资方式仍不明。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('149', 'world', '印巴交锋还将继续？莫迪：目前只是“暂停”军事行动', 'https://news.sina.com.cn/w/2025-05-13/doc-inewkmnf0510321.shtml', null, '印度总理莫迪发表电视讲话，宣布印度只是暂停对巴基斯坦的军事行动，并将采取报复措施。他强调监视巴基斯坦行动，拒绝核讹诈，提出未来谈判仅聚焦反恐与克什米尔问题。此次停火虽维持，但双方仍存紧张关系，美国称斡旋避免核冲突，而巴方否认主动求和，重申主权受侵时将全面报复。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('150', 'finance', '习近平同巴西总统卢拉会谈', 'https://finance.sina.com.cn/china/2025-05-13/doc-inewmnxr4217973.shtml', null, '中巴元首会谈深化命运共同体建设，习近平提出坚持战略互信、扩大合作、人文交流和多边协作四点建议，推动经贸、科技、农业等领域合作。卢拉赞赏中国支持，愿对接“一带一路”，加强国际事务协作。双方签署20份合作文件，发表联合声明，反对单边主义，支持乌克兰危机和平解决。会谈后举行欢迎仪式和宴会。（99字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('151', 'finance', '中巴联合声明（全文）', 'https://finance.sina.com.cn/china/2025-05-13/doc-inewmnxr4219218.shtml', null, '中巴发布联合声明，宣布强化构建命运共同体，深化经贸、科技、农业、能源等领域合作，推动多边主义和国际秩序改革。双方支持联合国、世贸组织等机构改革，反对单边主义，承诺维护全球产业链稳定。巴方重申一中原则，中方支持巴西主办金砖峰会及气候大会。此外，两国将加强人工智能、网络空间治理合作，并推动解决巴以冲突等国际问题。卢拉访华期间签署多项合作文件。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('152', 'finance', '5月13日增减持汇总：盘后万向德农等2股增持 金埔园林等17股减持（表）', 'https://finance.sina.com.cn/stock/marketresearch/2025-05-13/doc-inewmtfs6801073.shtml', null, '5月13日盘后，A股市场2家公司（万向德农、黄河旋风）披露增持计划，17家公司（包括日月明、金埔园林等）公布减持动向。相关动态涉及农业、化工、医药等多个行业。新浪财经提醒投资者注意风险，信息仅供参考不构成投资建议。（98字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('153', 'finance', '中巴续签双边本币互换协议有何意义？一文解读', 'https://finance.sina.com.cn/jjxw/2025-05-13/doc-inewmtfu1770313.shtml', null, '中国人民银行与巴西央行续签双边本币互换协议，规模为1900亿元人民币/1570亿雷亚尔，有效期5年。此举旨在深化中巴贸易合作，促进人民币在拉美使用，增强金融稳定。目前中国已与42个国家和地区签署本币互换协议，有效协议32份，总规模达4.3万亿元人民币，覆盖全球主要经济体。（98字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('154', 'finance', '市场监管总局等五部门约谈京东、美团、饿了么等外卖平台企业', 'https://finance.sina.com.cn/china/2025-05-13/doc-inewmnxw1878687.shtml', null, '市场监管总局联合四部门约谈京东、美团、饿了么等平台，要求其严格遵守《电子商务法》《反不正当竞争法》等法规，落实主体责任，规范经营行为，保障消费者、商户及骑手权益，促进公平竞争与行业健康发展。（98字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('155', 'finance', '科技', 'http://tech.sina.com.cn/', null, '', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('156', 'finance', '特朗普与苹果CEO库克通话 据报iPhone今年晚些时候或涨价', 'https://cj.sina.cn/article/norm_detail?url=https%3A%2F%2Ffinance.sina.com.cn%2Fstock%2Fusstock%2Fc%2F2025-05-13%2Fdoc-inewkfei0624752.shtml', null, '苹果考虑因新功能和设计上调新款iPhone售价，同时避免与美关税关联。特朗普称与库克通话，提及苹果或扩大在美投资建厂。此前关税已推高iPhone制造成本，库克预计本季将承担9亿美元额外关税成本。自2017年iPhone X起旗舰机型起售价未变，但成本压力增加。库克曾成功游说特朗普政府豁免部分产品关税。（99字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('157', 'finance', '小米SU7 Ultra风波升级：数百名车主要求退车，车主喊话雷军保持真诚', 'https://finance.sina.com.cn/jjxw/2025-05-13/doc-inewkmnh7285675.shtml', null, '小米SU7 Ultra车主集体维权，指控4.2万元选装的碳纤维双风道前舱盖实际功能与宣传不符（风道未连接散热系统），要求退车。小米致歉并补偿2万积分或改配铝制机盖，但车主不满补偿力度及改配周期。法律专家指出小米涉嫌不当宣传，车主可依法索赔。同期小米首款SUV YU7即将上市，但负面舆情或影响其高端市场表现。（99字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('158', 'finance', '115网盘提现不到账', 'https://tousu.sina.com.cn/complaint/view/17382874289/?sld=7e4ab75ccb8145ee8cf6a659cc37fcab', null, '', '2025-05-14 03:17:46');
