INSERT INTO `news` VALUES ('166', 'ent', '塔科夫斯基：最美好的主场记忆是德比战打进绝平，击败枪手也很棒', 'https://k.sina.com.cn/article_2018499075_784fda0302002co26.html?from=sports&subch=osport', null, '埃弗顿后卫塔科夫斯基分享古迪逊公园球场记忆：最早印象是鲁尼绝杀阿森纳，首球为22-23赛季头球攻破枪手；最佳氛围属保级战和德比胜利，最美好记忆是本赛季德比压哨扳平。他盛赞球场\"沸腾、激情、充满活力\"，最爱本赛季球衣和球迷歌曲《蓝色精神》，并调侃对理查利森的争议铲球趣事。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('167', 'ent', '埃弗拉：曼联本赛季是灾难阿莫林带来了纪律 没B费曼联可能降级', 'https://k.sina.com.cn/article_2018499075_784fda0302002co78.html?from=sports&subch=osport', null, '曼联名宿埃弗拉称本赛季是“灾难”，但认可主帅阿莫林带来的纪律性和改进，强调需时间适应。他盛赞B费是关键球员，认为欧冠资格对引援至关重要，呼吁下赛季重整旗鼓，对未来谨慎乐观。（99字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('168', 'ent', '天空：曼城就维尔茨转会达口头协议，药厂不想将其出售给拜仁', 'https://k.sina.com.cn/article_2018499075_784fda0302002co76.html?from=sports&subch=osport', null, '曼城与勒沃库森就德国前锋维尔茨（22岁）转会达成口头协议，药厂倾向将其出售给曼城而非拜仁。拜仁仍在积极争取，但维尔茨尚未决定未来。本赛季他44场贡献16球14助，德转身价1.4亿欧。（98字）', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('169', 'ent', '时光如流水，安切洛蒂1994年作为意大利助教见证巴西夺世界杯冠军', 'https://k.sina.com.cn/article_2018499075_784fda0302002co74.html?from=sports&subch=osport', null, '1994年世界杯决赛，巴西通过点球大战3-2击败意大利，第四次夺冠。意大利队巴雷西、马萨罗和巴乔罚失点球，时任助教安切洛蒂回忆称，他原以为巴乔和巴雷西不会失手，甚至调侃仍在寻找巴雷西射飞的球。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('170', 'ent', '?ESPN：俱乐部不承担，阿莫林自费请30名后勤及家属看欧联决赛', 'https://k.sina.com.cn/article_2018499075_784fda0302002co72.html?from=sports&subch=osport', null, '曼联主帅阿莫林自费为30名后勤团队成员及家属购买欧联杯决赛门票，此前俱乐部要求员工自行购票。曼联正推行成本削减措施，仅提供员工两张购票资格，而巴黎圣日耳曼则为600名员工提供免费欧冠决赛观赛机会。阿莫林此举旨在奖励团队在困难时期的付出。曼联称限制门票是为保障球迷购票机会。', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('171', 'ent', '大乐透预测-财叔中2等55万累擒1809万', 'https://lottery.sina.com.cn/number/?from=xw', null, '', '2025-05-14 03:17:46');
