INSERT INTO `news` VALUES ('173', 'ent', 'CS更新0513：地图版本更新、UI音效重置', 'http://games.sina.com.cn/news/yw/2025-05-13/esports-inewmhrt4269527.shtml', null, '', '2025-05-14 03:17:46');
INSERT INTO `news` VALUES ('174', 'hot', '以家庭的好家风支撑起全社会的好风气', 'https://news.sina.com.cn/gov/xlxw/2025-05-15/doc-inewruvx9413141.shtml', null, '习近平总书记强调家庭建设对国家发展、社会和谐的重要性，指出家庭的前途命运与民族、国家紧密相连。他倡导注重家教、家风，弘扬家国情怀，将个人梦融入国家梦。要求家长以身作则，培养子女品德，领导干部更应严格家风，防止特权腐败。通过优良家风推动社会风气建设，激励后代成长为有用之才。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('175', 'hot', '俄方谈判代表团已抵达土耳其伊斯坦布尔', 'https://news.sina.com.cn/w/2025-05-15/doc-inewrkhc9608606.shtml', null, '俄方谈判代表团已抵达土耳其伊斯坦布尔，俄乌中断3年的直接谈判有望于5月15日重启，预计莫斯科时间10时开始。塔斯社援引消息人士报道了这一进展。（总台记者 王德禄）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('176', 'hot', '病重老人在银行取钱时去世 家属发声', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrkha0169507.shtml', null, '湖南株洲62岁病重老人因存单密码遗忘，家属代取被拒，银行坚持要求老人亲自到场。5月14日，老人坐轮椅办理业务近1.5小时后不幸离世，银行当晚仍完成取款操作。家属质疑银行流程不合理，涉事农行称以警方调查为准，警方暂未回应。事件引发舆论关注。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('177', 'hot', '外媒：美国反对邀请泽连斯基参加北约峰会', 'https://news.sina.com.cn/w/2025-05-15/doc-inewrcye0234855.shtml', null, '【摘要】美方反对邀请乌总统泽连斯基参加6月北约海牙峰会，若成行将系俄乌冲突后其首次缺席。报道称此举为避与特朗普矛盾，议程缩至国防议题，或改办外长级会议替代。盟友普遍惊讶，但最终决定仍存变数。特朗普此前多次质疑乌克兰加入北约的可行性。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('178', 'hot', '金价失守3200美元 黄金何时止跌企稳？', 'https://news.sina.com.cn/o/2025-05-15/doc-inewqxsh0306622.shtml', null, '【黄金市场动态摘要】国际金价近期承压，因贸易乐观情绪削弱避险需求，纽约期金跌破3200美元。中国4月黄金ETF流入创纪录（490亿元），但5月放缓。全球黄金ETF规模达3790亿美元，央行持续购金。短期金价受获利回吐和地缘风险降温影响，但长期仍受机构配置和经济不确定性支撑。市场关注美联储降息预期及通胀数据。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('179', 'hot', '纯净水由今麦郎代工？娃哈哈最新回应', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrcye0246668.shtml', null, '【娃哈哈回应代工争议】针对“纯净水由今麦郎代工”的热议，娃哈哈客服回应称，全国（除海南外）均有生产基地，代工产品符合自身质量标准，包装差异属正常，可放心饮用。今麦郎确认按娃哈哈标准生产。娃哈哈强调其纯净水达国家实验室用水级别（电导率≤10μS/cm）。网友对代工模式看法不一。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('180', 'mil', '观•点｜在江苏 打开博物馆的N种方式', 'https://news.sina.com.cn/zx/gj/2025-05-15/doc-inewrqpz9487363.shtml', null, '江苏博物馆创新融合传统文化与年轻元素，通过数字化展览、跨界活动（如戏曲咖啡、汉服打卡）、科技互动（VR/AR、全息成像）及特色文创（明信片、冰箱贴）吸引年轻人。2024年参观人数达1.4亿，居全国首位，展现文博活力与未来趋势。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('181', 'mil', '姜同学，你在人生大考中已获“满分”', 'https://news.sina.com.cn/zx/gj/2025-05-15/doc-inewrkhc9601327.shtml', null, '山东考生姜昭鹏赴考途中因护送突发心梗同学就医错过考试，其\"同学的生命只有一次\"的言行获赞。当地启用副题为其安排补考，此举被赞为\"制度温度与公众期待的双向奔赴\"，彰显教育培养担当人才的本质，传递\"有德者有得\"的价值观。网友称其\"人生大考已获满分\"。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('182', 'mil', '守护经济安全 护航金融高质量发展——专访公安部经济犯罪侦查局相关负责人', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewprww0954054.shtml', null, '2024年全国公安机关破获经济犯罪案件7.8万起，涉案超8000亿元，重点打击非法集资、网络传销等犯罪。公安部部署金融领域“黑灰产”6个月专项打击，并创新“金析为证”机制破解新型犯罪证据难题。同时推出“便民利企十项指引”，优化营商环境，多地推出护企举措，保障经济安全发展。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('183', 'mil', '61.2亿元！今年前4个月海南与拉美地区国家进出口创历史同期新高', 'https://news.sina.com.cn/zx/gj/2025-05-15/doc-inewruwc2073253.shtml', null, '海南与拉美贸易合作持续深化，前4个月进出口61.2亿元，同比增长7.9%，创历史新高。巴西原油等生产资料及牛肉、咖啡等特色产品进口增长显著，海南石化产品、水产品等加速出口拉美。海口海关将优化通关便利措施，助力双边经贸高质量发展。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('184', 'mil', 'YouthLens | 中国技术+巴西农业，绿茵场外的大国“粮”策', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewpmqy1042607.shtml', null, '中巴元首会谈后发布联合声明，同意加强科技创新合作，重点推动农业现代化。巴西部长考察中国农大“中巴科技小院”项目，肯定“中国技术+巴西农业”模式提升种植效益。两国青年通过《Youth Lens》节目展开跨文化交流，共促南南合作新篇章。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('185', 'mil', '云南昭通：“花海经济”绽放“幸福产业”', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewpmra0453840.shtml', null, '云南省威信县麟凤镇依托生态优势，发展1100亩芍药种植基地，涵盖68个畅销品种，形成“种加销”全产业链。基地带动当地群众通过土地流转、务工增收，年发放工资近300万元，高峰期用工超150人。未来计划扩种至万亩，打造“芍药小镇”，推动“花海经济”助力乡村振兴。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('186', 'mil', '第二届东北图书交易博览会主会场场馆大揭秘！精彩抢先看', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewpmqy1047488.shtml', null, '第二届东北图书交易博览会将于5月15日—19日在长春农业博览园举办，主题为“书香向北 阅见未来”。主会场设四大主题展馆、12个展区，涵盖出版、文化、非遗等内容，重点活动包括5月16日的“中俄文化对话”。另设18个分会场。活动面向公众开放，旨在推动文化交流。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('187', 'mil', '青春创未来  突破豪车级涂层技术获百万元创业投资', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewnuth1246862.shtml', null, '中南林业科技大学研究生李岳琦团队突破国际垄断，研发出高性能低成本金属陶瓷涂层技术，性能对标保时捷，成本仅为进口产品的30%-40%，已获吉利汽车、中国航天等合作及百万创业投资。该技术使制动盘减重30%，耐磨性超国内标准，并应用于航空航天领域。团队目标进军国际高端市场，推动国产新材料产业发展。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('188', 'mil', '世界数字教育大会是个什么会？AI毕昇告诉你', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewnuth1283348.shtml', null, '2025世界数字教育大会将于5月14日在武汉开幕，聚焦智能时代教育变革。中国数字教育成效显著，中小学基本实现网络覆盖，智慧教育平台共享优质资源。湖北作为教育大省，展示AI、VR等技术在教育中的创新应用，如智能皮影、数字孪生校园等。大会旨在推动全球数字教育发展，解决教育公平与资源共享问题。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('189', 'mil', '外媒观察|中国发布首部国家安全白皮书，强调不实施安全胁迫也不接受威胁施压', 'https://news.sina.com.cn/zx/gj/2025-05-14/doc-inewnuth1243191.shtml', null, '中国国务院发布《新时代的中国国家安全》白皮书，阐述总体国家安全观及实践成果，强调统筹发展与安全，为世界注入稳定性。白皮书提出全球安全倡议，倡导共同安全与多边合作，反对安全胁迫。外媒关注中国维护主权、推动高质量发展及全球安全治理的立场。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('190', 'china', '中方敦促美方尽快停止232关税措施', 'https://news.sina.com.cn/c/2025-05-15/doc-inewruvx9421325.shtml', null, '商务部在例行发布会上批评美方对进口汽车、钢铝加征232关税及发起药品232调查，指责其行为是单边主义和保护主义，损害他国利益并破坏多边贸易体系，同时无助于美国产业。中方敦促美方停止相关措施，通过平等对话解决分歧。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('191', 'china', '商务部谈中美经贸会谈下一步情况', 'https://news.sina.com.cn/c/2025-05-15/doc-inewruvv9985110.shtml', null, '5月10日至11日，中美经贸高层在日内瓦举行会谈，中方牵头人何立峰与美方代表贝森特、格里尔进行深入沟通，达成《中美日内瓦经贸会谈联合声明》。会谈落实中美元首通话共识，取得实质性进展。双方同意就经贸关切保持沟通。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('192', 'china', '商务部介绍中美经贸磋商机制', 'https://news.sina.com.cn/c/2025-05-15/doc-inewruvv9981331.shtml', null, '商务部表示中方始终开放通过对话解决中美经贸问题，双方已同意建立磋商机制以保持沟通。具体消息将适时发布。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('193', 'china', '中央指导组进驻后，当地点名通报6人', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrkhc9612640.shtml', null, '中央第三指导组督导常德落实中央八项规定精神，强调从严整改突出问题。5月15日，常德通报4起顶风违纪案例：桃源县、澧县官员违规公款吃喝及接受宴请；武陵区公职人员擅离职守打牌；临澧县干部醉驾被立案。相关责任人受党纪政务处分，彰显对顶风违纪“零容忍”态度。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('194', 'china', '北京网络辟谣宣传月│ 解码网络谣言之识别篇', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrkha0142271.shtml', null, '北京网络举报提醒，网络谣言扰乱生活、污染生态、危害稳定，呼吁网民熟悉常见套路以更好识别。倡导还原事实、洞悉真相，鼓励关注并举报谣言。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('195', 'china', '哪吒汽车创始人方运舟被冻结2000万元股权', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrcxy8459820.shtml', null, '合众新能源汽车股份有限公司（哪吒汽车）5月13日新增2000万元股权冻结，创始人方运舟为被执行人，冻结期至2028年。该公司近日被申请破产审查，并存在多条被执行人、限消令及股权冻结信息。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('196', 'china', '宇树科技申请“机器人牌照”商标', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrcya5226286.shtml', null, '杭州宇树科技近日申请注册“机器人牌照”“机牌”等商标，涉及科学仪器、运输工具等类别，目前状态为等待实质审查。该公司成立于2016年，由王兴兴、汉海信息、红杉科盛等共同持股，注册资本约259.42万元。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('197', 'china', '我国牵头制定，适老化数字经济国际标准发布', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrcyf9660582.shtml', null, '我国牵头制定的ISO首个人口老龄化数字经济标准《老龄化社会 老龄化包容性数字经济通用要求与指南》（ISO 25556：2025）正式发布。该标准针对老年人高频数字场景提出解决方案，获20多国专家参与，旨在缩小全球老年人数字鸿沟。目前全球60岁及以上人口达14.2亿。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('198', 'china', 'A股三大指数集体低开', 'https://news.sina.com.cn/c/2025-05-15/doc-inewrcxy8429158.shtml', null, '\n　　来源：财联社\n　　财联社5月15日电，沪指低开0.16%，深成指低开0.28%，创业板指低开0.34%，大金融、贵金属等板块指数跌幅居前。\n责任编辑：刘德宾 \n', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('199', 'china', '国台办这样回应特朗普，特别有意思！', 'https://news.sina.com.cn/c/2025-05-15/doc-inewqxsh0314478.shtml', null, '特朗普在5月12日白宫记者会上谈及对华贸易谈判时，突然提到“统一与和平”（unification），引发岛内对谈判涉及台湾议题的猜测。国台办回应称，希望国际社会更广泛支持中国反“台独”及统一事业，并强调美国应遵守一中原则。台媒分析认为，特朗普言论可能暗示对两岸统一的立场，而民进党当局试图篡改人口统计的行为被批荒谬。中方重申台湾是中国领土不可分割的一部分。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('200', 'china', '直奔目标空域！看战鹰身披霞光呼啸升空', 'https://news.sina.com.cn/c/2025-05-15/doc-inewqxsh0304298.shtml', null, '空军某部近日多次组织实弹射击训练，战机在霞光中升空执行任务。相关报道重复强调训练场景，未提及具体时间、地点及机型，内容高度雷同，可能为标准化宣传通稿。专题链接指向日常军事新闻栏目。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('201', 'china', '为躲冰雹把车停桥下致严重拥堵，违法吗？律师解读', 'https://news.sina.com.cn/c/2025-05-15/doc-inewqpan0519941.shtml', null, '北京突降冰雹，部分车主为躲避冰雹将车停在天桥下导致严重拥堵，引发网友争议。律师指出，该行为不属于紧急避险，涉嫌违法停车，因未满足\"不得已而为之\"和\"未超必要限度\"条件，且损害公共利益。冰雹损失属车损险范围，但若因违停导致损失加重，保险公司可能拒赔。法律强调极端天气下应减速行驶，公共利益优先于个人财产保护。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('202', 'china', '商务部新闻发言人就出口管制管控名单答记者问', 'https://news.sina.com.cn/c/2025-05-14/doc-inewqans0740719.shtml', null, '商务部宣布，为落实中美经贸会谈共识，自2025年5月14日起暂停对28家美国实体的出口管制措施，为期90天。期间企业需按条例申请两用物项出口许可，商务部将依法审批。此前4月，这些实体因违反出口管制法规被列入管控名单。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('203', 'world', '普京召开俄乌谈判筹备会议', 'https://news.sina.com.cn/w/2025-05-15/doc-inewrqpz9492315.shtml', null, '俄罗斯总统普京14日晚主持筹备与乌克兰谈判的会议，俄方参会人员包括外长拉夫罗夫、国防部长别洛乌索夫等高官。乌方官员表示双方尚未就谈判开始时间达成一致。（总字数：60字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('204', 'world', '扬其国威，印度向70国通报“战果”', 'https://news.sina.com.cn/w/2025-05-15/doc-inewrqqc5419421.shtml', null, '印度国防情报局局长拉纳向70国外交官通报“朱砂行动”成功。印执政党人民党启动10天全国胜利宣讲活动以激发民族自豪感，但遭反对党批评。新闻关联印巴停火专题。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('205', 'world', '韩国总统选举趋近 候选人安保“与总理同级别”', 'https://news.sina.com.cn/w/2025-05-15/doc-inewrcya5225359.shtml', null, '韩国总统选举将于6月3日举行，7名候选人安保升级。警方部署反狙击设备、增派180名安保人员，并对候选人实施24小时\"次最高级\"保护。最大在野党候选人李在明因传闻面临暗杀威胁，其支持率51%领先。执政党候选人金文洙支持率31%。去年李在明曾遇袭，警方将在投票日动员16.8万警力确保选举安全。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('206', 'world', '超2435亿美元！美国和卡塔尔签协议', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqxse5299799.shtml', null, '美国与卡塔尔签署总额超2435亿美元的经济及军事合作协议，包括卡塔尔航空960亿美元采购波音客机，以及30亿美元军购（含无人机及反无人机系统）。双方还达成能源和高科技合作。特朗普访卡期间确认两国盟友关系，卡塔尔乌代德基地为美中东最大军事基地。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('207', 'world', '巴基斯坦这个举动，印度更是五味杂陈', 'https://news.sina.com.cn/w/2025-05-15/doc-inewrcya5198925.shtml', null, '巴基斯坦于5月14日释放一名被俘印度士兵，延续2019年缓和冲突的善意姿态。印度国内反应复杂：莫迪政府高调宣扬军事胜利并启动爱国宣传活动，部分民众则因战果争议及盟友倒向巴方感到愤怒。双方虽仍言辞交锋，但已遵守停火协议。经济学家警告持续冲突或致两国损失5000亿美元，呼吁避免核武邻国间的战争风险。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('208', 'world', '韩媒：选举压力下，尹锡悦被要求退出国民力量党', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqtkk0407380.shtml', null, '韩国总统选举临近，国民力量党因候选人金文洙与李在明支持率差距较大，党内要求前总统尹锡悦退党呼声高涨。尹锡悦此前发表动员声明引发党内危机感，部分高层敦促其主动退党，否则将采取强制措施。民调显示李在明支持率51%领先，金文洙31%居次。国民力量党希望解决尹锡悦党籍问题以争取中间选民，但内部意见分歧，尹锡悦或主动退党。党内外矛盾加剧选举不确定性。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('209', 'world', '英媒：呼吁自由贸易，瑞典推欧盟加入CPTPP', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqtkm9842401.shtml', null, '瑞典拟推动欧盟加入CPTPP以应对美国关税冲击，认为此举将形成全球最大自贸区，助力欧盟开放贸易。瑞典外贸大臣杜萨承认欧盟内部分歧（如法国保护主义），但强调对瑞典经济至关重要。欧盟委员会主席冯德莱恩视其为应对美国贸易压力的\"B计划\"。分析称加入CPTPP可提升欧盟GDP0.3%-0.5%，并增强对美谈判筹码。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('210', 'world', '问责！美海军对“杜鲁门”号航母一系列事故展开调查', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqxse5305515.shtml', null, '美国海军“哈里·杜鲁门”号航母近期事故频发：5月6日和4月28日，两架F/A-18“超级大黄蜂”舰载机相继坠海，2月曾与商船碰撞，去年12月还发生友军误击战机事件。专家分析称，高强度的反胡塞武装作战及过渡机型超负荷任务导致飞行员疲劳操作，加之躲避导弹等压力，增加了事故风险。美海军正调查并计划问责整改。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('211', 'world', '消息人士称泽连斯基已启程前往土耳其', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqpah8761804.shtml', null, '乌克兰总统泽连斯基14日启程访问土耳其。同日，俄罗斯总统普京确定俄乌谈判俄方代表团名单，成员包括总统助理梅津斯基、外交部副部长加卢津等8人。双方动向显示俄乌冲突相关外交活动持续。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('212', 'world', '普京确定俄乌谈判俄方代表团名单', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqpap9960058.shtml', null, '俄罗斯总统普京14日确定俄乌谈判俄方代表团名单，成员包括总统助理梅津斯基等6名官员及4名专家。同日，乌克兰总统泽连斯基被曝已启程前往土耳其。消息显示双方或为新一轮接触做准备。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('213', 'world', '证实了：F-35险被导弹击中', 'https://news.sina.com.cn/w/2025-05-15/doc-inewqxse5289650.shtml', null, '美媒爆料称，特朗普政府与胡塞武装停火或因军事行动受阻。《纽约时报》称美军F-16、F-35战机曾险遭胡塞导弹击中，\"战区\"网站披露F-35被迫紧急规避细节。胡塞武装使用苏制技术改进的防空导弹（最大射程70公里），美官员评价其\"技术不先进但创新性强\"。目前尚不清楚涉事F-35的具体型号。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('214', 'finance', '外交部介绍对巴西、阿根廷、智利、秘鲁、乌拉圭等5国试行免签政策', 'https://finance.sina.com.cn/china/2025-05-15/doc-inewrqqc5413900.shtml', null, '中国外交部宣布，自2025年6月1日至2026年5月31日，对巴西、阿根廷、智利、秘鲁、乌拉圭五国持普通护照人员试行30天内免签政策，涵盖商务、旅游、探亲等短期活动。此举旨在提升中外人员往来便利化水平，展现中国高水平对外开放态度，并鼓励外国民众赴华体验多元文化。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('215', 'finance', '特朗普施压库克：不希望苹果在印度建厂！', 'https://finance.sina.com.cn/stock/relnews/us/2025-05-15/doc-inewrqqf2202214.shtml', null, '特朗普施压苹果CEO库克，要求减少印度生产并扩大美国制造，直接叫停苹果在印建厂计划。苹果此前宣布将大部分美国市场产品转至印度和越南生产以规避关税压力，但特朗普干预后承诺增加本土产能。库克透露关税已致苹果季度成本增加9亿美元，但未明确是否转嫁消费者。美印贸易谈判背景下，苹果供应链多元化战略遇阻。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('216', 'finance', '病重老人被要求亲自取钱在银行门口去世？亲属发声、银行回应', 'https://finance.sina.com.cn/wm/2025-05-15/doc-inewrkha0164391.shtml', null, '湖南株洲一名重病患者在银行取款时不幸身亡。家属称患者曾委托女儿取款被拒，银行要求本人到场，患者被轮椅推至银行后因业务延迟身体不适，最终在门外透气时离世。银行回应称因密码重置需本人办理，已安抚家属并安排住宿。警方介入调查。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('217', 'finance', '特朗普中东行“冷落”亲密盟友，以色列有怒不敢言', 'https://finance.sina.com.cn/roll/2025-05-15/doc-inewrqpz9540783.shtml', null, '特朗普本周中东行绕过以色列，重点与海湾国家推进商业协议，引发以方不安。美以在伊朗谈判、也门停火及加沙人质谈判等问题上分歧明显，以色列担忧被边缘化。内塔尼亚胡政府保持沉默，但坚持加沙军事行动。特朗普称其政策长远利好以色列，但以媒认为中东格局重塑中以色列沦为旁观者。美方强调同盟牢固，但私下对以方立场不满。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('218', 'finance', '工厂停工、员工投诉维权！娃哈哈最新回应', 'https://finance.sina.com.cn/roll/2025-05-15/doc-inewrqqf2173098.shtml', null, '娃哈哈回应工厂停工及代工争议，称因产能紧张调整产销布局，部分工厂已依法清算，并完成18条新产线布局以保障供应。针对员工维权，公司表示安置合法合规。此外，娃哈哈承认曾委托今麦郎代工纯净水，但因个别批次质检问题已于2025年4月终止合作，强调在售产品均符合标准。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('219', 'finance', '科技', 'http://tech.sina.com.cn/', null, '', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('220', 'finance', '销量承压，生态缺位，COLMO如何挑起美的高端化？', 'https://finance.sina.com.cn/tech/roll/2025-05-15/doc-inewprwy0372450.shtml', null, '2025年家电市场呈现“冰火两重天”：美的、格力、海尔三巨头营收利润双增，但线下经销商因价格战和电商冲击陷入困境，超50%门店或面临闭店。美的旗下高端品牌COLMO面临品牌认知低、下沉难、价格混乱、套系化销售受阻等问题，叠加生态短板与AI家电落地难，冲高前景存疑。行业整体向“剩者为王”格局演变。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('221', 'finance', '小米SU7 Ultra风波升级：数百名车主要求退车，车主喊话雷军保持真诚', 'https://finance.sina.com.cn/jjxw/2025-05-13/doc-inewkmnh7285675.shtml', null, '小米SU7 Ultra车主集体维权，指控4.2万元选装的碳纤维双风道前舱盖实际功能与宣传不符（风道未连接散热系统），要求退车。小米致歉并补偿2万积分或改配铝制机盖，但车主不满补偿过低且改配需重新排队。法律专家指其宣传涉嫌违规，车主可依法索赔。同期小米首款SUV YU7即将上市，但负面舆情或影响销量。小米1-4月累计销量超10万辆，但雷军IP绑定策略在危机中放大舆论风险。（99字）', '2025-05-15 16:42:52');
