INSERT INTO `news` VALUES ('231', 'ent', '魅力十足卡里乌斯妻子惊艳亮相慈善晚宴，还与巴乔合影', 'https://k.sina.com.cn/article_2018499075_784fda0302002cql4.html?from=sports&subch=osport', null, '卡里乌斯妻子迪莱塔·莱奥塔在AC米兰对阵博洛尼亚的意大利杯决赛前夜出席慈善晚宴，身着紧身花裙搭配银饰，造型惊艳，其930万粉丝的Ins账号引发热议。33岁的莱奥塔与足坛传奇巴乔合影，她于2022年与卡里乌斯相恋，2023年8月诞下女儿。（99字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('232', 'ent', '阿森纳官方：拉亚下赛季改穿1号球衣，恩瓦内里接过22号战袍', 'https://k.sina.com.cn/article_2018499075_784fda0302002cql0.html?from=sports&subch=osport', null, '阿森纳官方宣布，门将拉亚将在2025/26赛季改穿1号球衣，接替此前多位传奇门将的号码；18岁攻击手恩瓦内里则从53号改穿拉亚原用的22号球衣。两人新赛季号码调整延续了俱乐部相关号码的传统。（98字）', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('233', 'ent', '泰国羽毛球公开赛次轮，陈清晨/王汀戈、冯彦哲/黄东萍顺利晋级', 'https://k.sina.com.cn/article_2018499075_784fda0302002cqks.html?from=sports&subch=osport', null, '中国羽毛球组合在2025年泰国公开赛次轮表现强势：女双陈清晨/王汀戈以21-18、22-20击败泰国组合本雅帕/努特卡恩；混双冯彦哲/黄东萍以21-15、21-9轻取中国台北选手柏礼维/张净惠，两队均直落两局晋级下一轮。', '2025-05-15 16:42:52');
INSERT INTO `news` VALUES ('234', 'ent', '什么秋名山车神？切尔西后卫福法纳多次超速被扣47分，禁驾2年', 'https://k.sina.com.cn/article_2018499075_784fda0302002cqku.html?from=sports&subch=osport', null, '切尔西后卫福法纳因驾驶豪车多次超速被禁驾两年，累计扣分47分。他驾驶劳斯莱斯、奥迪和兰博基尼在限速路段超速，最高达90英里/小时。法庭判处其缴纳罚款等共计7569英镑，并因其惯犯行为延长禁驾期。福法纳未出庭，律师代其致歉，称其因疏忽交规而违法。（98字）', '2025-05-15 16:42:52');
