INSERT INTO `news` VALUES ('238', 'mil', '美国开发“轨道航母”危害太空安全', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewruvx9448488.shtml', null, '美国商业航天公司获太空军6000万美元合同，开发可搭载机动卫星的“轨道航母”，旨在提升太空作战快速响应能力。该项目将推进美军“动态太空行动”概念，强化卫星机动部署和战术响应，但可能加剧太空军事化风险。专家警告其武器化潜力或引发太空军备竞赛，威胁太空安全与治理。（99字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('239', 'mil', '又被帅到了！多视角感受空战对抗训练有多硬核', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewruvz5329573.shtml', null, '南部战区海军航空兵近日开展空战对抗训练，重点演练空战战术、空中扫荡及攻击海上目标等课目，旨在检验飞行员技战术水平，提升部队实战能力。（傅金泉等报道）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('240', 'mil', '中央军委决定调整组建3所军队院校', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewruvx9424708.shtml', null, '中央军委决定调整组建陆军兵种大学（合肥）、信息支援部队工程大学（武汉）、联勤保障部队工程大学（重庆）3所高等教育院校，面向社会招收高中毕业生。新院校由多所现有军校合并组建，具体招生信息将后续发布。此举旨在适应军兵种结构调整和军事人才培养需求。', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('241', 'mil', '国防部要求菲方停止一切侵权挑衅的危险举动', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewruvx9424771.shtml', null, '中国国防部回应菲律宾频繁侵闯黄岩岛事件，发言人蒋斌大校强调黄岩岛是中国固有领土，中方依法拦阻驱离菲方军舰，行动专业克制。指责菲方危险接近中方舰艇，威胁中国主权安全，要求菲方立即停止侵权挑衅，否则将承担后果。中方坚决维护领土主权和海洋权益。', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('242', 'mil', '中新两军联演进入海上实兵演练阶段', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewruvv9988808.shtml', null, '中新两军“合作-2025”海上联演5月14日进入海上实兵阶段，中国海军赤水舰、许昌舰赴预定海域展开为期2天的演练，内容包括通过雷区、舰炮射击、联合搜救及医疗后送等课目。（共60字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('243', 'mil', '国防部要求菲方停止一切侵权挑衅的危险举动', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewruvz5299195.shtml', null, '国防部回应菲律宾频繁派舰艇侵闯中国黄岩岛领海，发言人蒋斌大校强调黄岩岛是中国固有领土，中方依法拦阻驱离菲方挑衅行为，要求菲方停止侵权举动，警告其勿挑战中方维护主权决心，否则将自食其果。（98字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('244', 'mil', '第80集团军某旅按新条令规范智能电子设备管理', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewrqqf2170010.shtml', null, '第80集团军某旅按新修订的共同条令规范智能电子设备管理，允许官兵在休息日等个人时间使用实名登记的智能手表等设备，训练时集中保管。新条令明确保护隐私、规范使用场景，并禁止未经批准的监管。设备助力官兵科学健身和健康监测，旅队强调管用结合，发挥科技服务战斗力的作用。（98字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('245', 'mil', '内塔尼亚胡：以军将在未来几天“全力进入”加沙', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewrqpz9492913.shtml', null, '以色列总理内塔尼亚胡宣布以军将在未来几天全面进入加沙，旨在摧毁哈马斯。13日以军对加沙多地发动空袭，造成至少81人死亡（16+65），并袭击了汗尤尼斯医院，目标为哈马斯高官。以军要求加沙北部居民撤离，内塔尼亚胡称将战斗到底。联合国呼吁停火，多国批评以军行动，美国与以方立场现分歧。（99字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('246', 'mil', '美官员证实：一架F-35险被导弹击中', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewrcyf9670507.shtml', null, '美媒报道，美军在针对胡塞武装的\"莽骑兵\"行动中，一架F-35战机险些被其防空导弹击中，被迫采取规避动作。胡塞武装使用苏制技术改进的防空系统（射程50-70公里），虽技术不先进但战术灵活。目前无法确认涉事F-35型号（空军A型或海军C型）。此前特朗普突然宣布停火，或因军事行动受阻。（99字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('247', 'mil', '融入作战体系，他们紧紧锁住“敌”机', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewrcxy8459136.shtml', null, '南部战区空军地导某部在实兵演练中成功拦截\"敌\"机突袭。演练中，任务分队快速完成导弹部署、雷达反干扰及组网协同，精准摧毁目标。该部通过联合航空兵、雷达兵等部队开展体系对抗训练，探索出多套组网战法，显著提升体系作战能力。（98字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('248', 'mil', '英媒曝英国特种部队在阿富汗系统性杀害平民', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewqxsh0311429.shtml', null, '英媒调查揭露英国特种部队在阿富汗系统性杀害平民，包括熟睡者和儿童。退伍军人证词显示高层纵容犯罪，指挥体系崩溃，部队内部充斥攻击性与种族主义。前首相卡梅伦早获知相关报告，若查实涉案者将作为战犯受审。专家称暴行引发全球追责呼声，阿富汗民众强烈要求索赔。（98字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('249', 'mil', '英国谋求深度介入欧洲防务', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewqxsa8544553.shtml', null, '英国近期通过军演、军援乌克兰及参与欧洲防务项目（如“欧洲天空之盾”）积极介入欧洲安全事务，意图填补美国战略收缩后的空缺并重塑脱欧后影响力。但其国防预算紧张、军力不足，且受制于英美特殊关系及欧盟对战略自主的追求，长期领导力存疑。（99字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('250', 'mil', '俄媒：俄海军正组建一批无人系统团', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewqxsa8544471.shtml', null, '俄罗斯海军正组建多个无人系统团，配备空中无人机、无人艇等装备，执行侦察、打击及反水雷等任务。专家称这些部队将提升作战效率，可能编入各舰队，配备\"海鹰\"等无人机及无人艇，并需建立集中指挥体系以优化效能。预计至少组建5个团，覆盖俄主要舰队。（98字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('251', 'mil', '陆军某旅强化党委领战领训能力，激励官兵担当奋斗', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewqxse5294188.shtml', null, '陆军某旅党委聚焦备战打仗主责主业，强化领战领训能力，通过跟训复盘、问题整改、创新议战议训模式等措施，带头研战谋战。党委班子成员围绕战法创新、体系练兵等深入研讨，优化保障模式，破解训练难题，激励官兵提升打仗本领，推动部队战斗力建设取得实效。（98字）', '2025-05-15 18:11:47');
INSERT INTO `news` VALUES ('252', 'mil', '陆军某旅强化党委领战领训能力，激励官兵担当奋斗', 'https://mil.news.sina.com.cn/zonghe/2025-05-15/doc-inewqxse5294188.shtml', null, null, '2025-05-15 19:58:39');
